INSERT INTO `activities` VALUES (1,2,'mountaineering','Mountaineering','adventure','https://images.unsplash.com/photo-1551632811-561732d1e306?q=80&w=2070','Challenge yourself with technical climbing on some of the world\'s highest peaks, requiring advanced skills and mountaineering experience.','[\"Peak Climbing\", \"Technical Skills\", \"High Altitude\", \"Achievement\"]','Very Challenging','Apr-May, Sep-Oct','15-60 Days','[\"Everest\", \"Annapurna\", \"Manaslu\", \"Island Peak\"]','[]','[2, 1, 4]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(2,3,'adventure-sports','Adventure Sports','adventure','https://images.unsplash.com/photo-1540882082344-b273b04e2c2f?q=80&w=2070','Get your adrenaline pumping with exciting activities like paragliding, bungee jumping, white water rafting, and zip-lining.','[\"Paragliding\", \"Bungee Jumping\", \"White Water Rafting\", \"Zip-lining\"]','Easy to Moderate','Sep-May','1-7 Days','[\"Pokhara\", \"Kathmandu\", \"Chitwan\", \"Bandipur\"]','[6, 9]','[5, 12, 13]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(3,4,'jungle-safari','Jungle Safari','adventure','https://images.unsplash.com/photo-1558799401-1dcba79e728e?q=80&w=2072','Explore Nepal\'s rich wildlife in national parks and conservation areas, spotting rhinos, tigers, elephants, and exotic birds.','[\"Wildlife Viewing\", \"Elephant Safari\", \"Bird Watching\", \"Nature Photography\"]','Easy','Oct-Mar','2-5 Days','[\"Chitwan\", \"Bardia\", \"Koshi Tappu\", \"Parsa\"]','[]','[7, 14]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(4,5,'cultural-tours','Cultural Tours','cultural','https://images.unsplash.com/photo-1565537714828-9bbde8c42c3f?q=80&w=2070','Immerse yourself in Nepal\'s rich cultural heritage, visiting ancient temples, traditional villages, and UNESCO World Heritage sites.','[\"UNESCO Sites\", \"Ancient Temples\", \"Traditional Villages\", \"Local Festivals\"]','Easy','Year-round','1-10 Days','[\"Kathmandu\", \"Bhaktapur\", \"Patan\", \"Bandipur\"]','[4, 7]','[6, 9, 10, 11]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(5,6,'pilgrimage','Pilgrimage','cultural','https://images.unsplash.com/photo-1601999109497-ba1c7b6e0cfb?q=80&w=2070','Embark on spiritual journeys to sacred sites, including the holy Mount Kailash and Lake Mansarovar, and Buddhist monasteries.','[\"Sacred Sites\", \"Spiritual Experience\", \"Religious Ceremonies\", \"Meditation\"]','Moderate to Challenging','May-Sep','7-21 Days','[\"Tibet\", \"Lumbini\", \"Muktinath\", \"Gosaikunda\"]','[2]','[9, 1]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(6,7,'meditation-and-healing','Meditation & Healing','cultural','https://images.unsplash.com/photo-1506905925346-21bda4d32df4?q=80&w=2070','Find inner peace and rejuvenation through meditation retreats, yoga sessions, and traditional healing practices in serene environments.','[\"Meditation Retreats\", \"Yoga Sessions\", \"Ayurvedic Healing\", \"Mindfulness\"]','Easy','Year-round','3-14 Days','[\"Pokhara\", \"Kathmandu\", \"Nagarkot\", \"Dhulikhel\"]','[8]','[5, 6, 13]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(7,8,'volunteering','Volunteering','cultural','https://images.unsplash.com/photo-1559827260-dc66d52bef19?q=80&w=2070','Make a meaningful impact while traveling by participating in community development projects, teaching, and conservation efforts.','[\"Community Service\", \"Teaching Programs\", \"Conservation Work\", \"Cultural Exchange\"]','Easy to Moderate','Year-round','1-12 Weeks','[\"Kathmandu\", \"Pokhara\", \"Rural Villages\", \"Chitwan\"]','[]','[6, 5, 7]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(8,9,'city-tours','City Tours','cultural','https://images.unsplash.com/photo-1512453979798-5ea266f8880c?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','Explore modern cities and urban attractions, from iconic skyscrapers to luxury shopping districts and cultural landmarks.','[\"Iconic Architecture\", \"Shopping Districts\", \"Urban Culture\", \"Modern Attractions\"]','Easy','Year-round','1-7 Days','[\"Dubai\", \"Bangkok\", \"Singapore\", \"Kuala Lumpur\"]','[201]','[26, 12]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(9,11,'desert-safari','Desert Safari','adventure','https://images.unsplash.com/photo-1451337516015-6b6e9a44a8a3?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','Experience the thrill of desert adventures with dune bashing, camel riding, sandboarding, and traditional Bedouin camp experiences.','[\"Dune Bashing\", \"Camel Riding\", \"Sandboarding\", \"Desert Camping\"]','Moderate','Oct-Apr','1-3 Days','[\"Dubai\", \"Abu Dhabi\", \"Oman\", \"Jordan\"]','[202]','[26]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(10,10,'luxury-experiences','Luxury Experiences','luxury','https://images.unsplash.com/photo-1582672060674-bc2bd808a8b5?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','Indulge in premium experiences including private tours, fine dining, luxury accommodations, and exclusive access to high-end attractions.','[\"5-Star Hotels\", \"Private Tours\", \"Fine Dining\", \"Exclusive Access\"]','Easy','Year-round','3-10 Days','[\"Dubai\", \"Maldives\", \"Singapore\", \"Thailand\"]','[203]','[26, 13, 12]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55'),(11,18,'water-activities','Water Activities','adventure','','','[]','Moderate','Year-round','1 Day','[]','[]','[]',NULL,0,1,'2026-07-05 20:11:55','2026-07-05 20:11:55');
