INSERT INTO `sliders` VALUES (1,4,'Kailash Mansarovar Yatra','Sacred Journey to Mount Kailash and Lake Mansarovar','Kailash Mansarovar','https://images.unsplash.com/photo-1506905925346-21bda4d32df4?q=80&w=1920&h=1080&fit=crop','/video/1766036119824_1757086209295_kailash__1_.mp4',0,'Book Sacred Journey','/kailash-mansarovar','primary',1,1,1,NULL,'2026-07-05 20:11:56','2026-07-06 08:45:47'),(2,1,'Experience Nepal','Experience the Ultimate Adventure','Himalayas, Nepal','https://images.unsplash.com/photo-1506905925346-21bda4d32df4?q=80&w=1920&h=1080&fit=crop','/video/1766079680376_1218_4__1___1_.mp4',12,NULL,NULL,NULL,1,2,1,NULL,'2026-07-05 20:11:56','2026-07-06 08:45:47'),(3,2,'Everest Base Camp Trek','Journey to the World\'s Highest Peak','Everest Region, Nepal','/uploads/sliders/images/compressed_1762064251180__129882010_gettyimages-1188124902.jpg','',NULL,NULL,NULL,NULL,0,2,1,NULL,'2026-07-05 20:11:56','2026-07-05 20:11:56'),(4,3,'Cultural Heritage Tours','Explore Ancient Temples and Traditions','Kathmandu Valley, Nepal','/uploads/sliders/images/compressed_1762064261911_image_processing20190816-4-13ewvja.jpg','',NULL,NULL,NULL,NULL,0,3,1,NULL,'2026-07-05 20:11:56','2026-07-06 08:45:47');
