INSERT INTO `tours` VALUES (1,328,'6-days-vietnam-highlights-tour-da-nang-hoi-an-hanoi-halong-bay','6 Days Vietnam Highlights Tour – Da Nang, Hoi An, Hanoi & Halong Bay','','','Experience the best of Vietnam with this 6 Days Vietnam Highlights Tour, covering the country’s most iconic destinations including Da Nang, Ba Na Hills, Hoi An, Hanoi, and Halong Bay. This well-crafted itinerary offers a perfect balance of culture, nature, history, and relaxation.\n\nBegin your journey in Da Nang, exploring stunning coastal landscapes, Marble Mountains, and the famous Golden Bridge at Ba Na Hills. Discover the charm of Hoi An Ancient Town, enjoy a lantern boat ride, and experience local life at the Coconut Village. Fly to Hanoi to explore historical landmarks, bustling old quarters, and vibrant street culture.\n\nThe tour concludes with a scenic Halong Bay day cruise, where you’ll sail through dramatic limestone formations and visit breathtaking caves. Designed for couples, families, and first-time visitors, this Vietnam tour package ensures comfort, guided experiences, and unforgettable memories from start to finish.',0.00,NULL,1,0,NULL,'6 days',NULL,'8-12','',0.00,0,'January, February, March, April, November, December','/uploads/tours/6-days-vietnam-highlights-tour-da-nang-hoi-an-hanoi-halong-bay/tour_1769505116398.jpg','[\"/uploads/tours/6-days-vietnam-highlights-tour-da-nang-hoi-an-hanoi-halong-bay/tour_1769505222807.jpg\", \"/uploads/tours/6-days-vietnam-highlights-tour-da-nang-hoi-an-hanoi-halong-bay/tour_1769505309066.jpg\"]','[]','[\"Accommodation in twin/double sharing rooms with daily breakfast\", \"International & domestic airfare (economy class)\", \"Private air-conditioned transportation\", \"English-speaking local guides\", \"Halong Bay 4-hour private cruise with lunch\", \"Entrance fees as per itinerary\", \"E-Visa assistance\", \"2 bottles of mineral water per person per day\"]','[\"Tips for guides, drivers & cruise staff\", \"Travel insurance\", \"Personal expenses\", \"Meals not mentioned in itinerary\", \"Peak season surcharges\"]','[]','[{\"day\": 1, \"meals\": \"Breakfast\", \"title\": \"Arrival in Da Nang\", \"description\": \"Arrive at Da Nang International Airport and transfer to your hotel. After check-in, enjoy free time at leisure to relax or explore the city on your own. Overnight stay in Da Nang.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Da Nang – Ba Na Hills & Golden Bridge\", \"description\": \"After breakfast, travel to Ba Na Hills and enjoy a scenic cable car ride. Visit the iconic Golden Bridge, flower gardens, pagodas, French Village, and Fantasy Park. Return to Da Nang in the evening for overnight stay.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Da Nang City Tour – Marble Mountains – Hoi An Ancient Town\", \"description\": \"Explore Da Nang’s city highlights including Son Tra Peninsula, Lady Buddha, and My Khe Beach. Continue to Marble Mountains and Coconut Village for a bamboo basket boat experience. In the evening, visit Hoi An Ancient Town and enjoy a lantern boat ride. Overnight stay in Da Nang.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Da Nang – Flight to Hanoi – City Tour\", \"description\": \"After breakfast, fly to Hanoi and check in at the hotel. Visit major attractions including the Ho Chi Minh Complex, One Pillar Pagoda, Hoan Kiem Lake, and the Old Quarter. Enjoy free time in the evening. Overnight stay in Hanoi.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Hanoi – Halong Bay Day Cruise\", \"description\": \"Travel to Halong Bay for a scenic day cruise through limestone islands. Visit caves, enjoy a seafood lunch on board, and admire the natural beauty of this UNESCO World Heritage Site before returning to Hanoi for overnight stay.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Departure from Hanoi\", \"description\": \"After breakfast, check out from the hotel and transfer to the airport for departure. End of the tour.\", \"accommodation\": \"3-Star Hotel\"}]','\"\"','[\"Vietnam\"]','[\"Cultural Tours\", \"Water Activities\", \"City Tours\"]',NULL,NULL,NULL,1,1,'2026-01-27 09:15:16','2026-01-27 09:31:38'),(2,326,'6-nights-7-days-kathmandu-pokhara-nagarkot','6 Nights 7 days Kathmandu- Pokhara-Nagarkot','','','Experience Nepal’s cultural heritage and natural beauty on this 6 Nights / 7 Days Kathmandu – Pokhara – Nagarkot Tour. Discover ancient temples and UNESCO World Heritage Sites in Kathmandu, enjoy breathtaking Himalayan views and lakeside relaxation in Pokhara, and unwind in Nagarkot, famous for its stunning sunrise and panoramic mountain vistas. A perfect blend of culture, nature, and serenity, ideal for couples, families, and leisure travelers.',0.00,NULL,1,0,NULL,'7 days',NULL,'2-8 people','',0.00,0,'','/uploads/tours/6-nights-7-days-kathmandu-pokhara-nagarkot/tour_1766900195833.jpg','[\"/uploads/tours/6-nights-7-days-kathmandu-pokhara-nagarkot/tour_1766900460234.jpg\", \"/uploads/tours/6-nights-7-days-kathmandu-pokhara-nagarkot/tour_1766900460251.jpg\", \"/uploads/tours/6-nights-7-days-kathmandu-pokhara-nagarkot/tour_1766900460264.jpg\"]','[\"Explore UNESCO World Heritage Sites in Kathmandu, including ancient temples and historic squares\", \"Enjoy spectacular Himalayan views and serene boating at Phewa Lake, Pokhara\", \"Witness a breathtaking sunrise over the Himalayas from Nagarkot\", \"Experience the natural beauty of Pokhara Valley with mountain and lake scenery\", \"Visit famous cultural landmarks such as Swayambhunath and Pashupatinath\", \"Comfortable accommodations with scenic drives across Nepal’s countryside\"]','[\"Traditional Welcome drink on arrival (Nonalcoholic)\", \"03 Nights’ accommodation at Kathmandu Hotel\", \"02 Nights’ accommodation at Pokhara Hotel\", \"01 Nights’ accommodation at Nagarkot Hotel\", \"1-liter mineral water per day\", \"Sunrise tour at Pokhara Pumdikot Shiva Temple.\", \"Arrival and departure transfer with assistance by A/C Vehicle\", \"All sightseeing and excursions as mentioned in the itinerary\", \"All transfers & sightseeing by private air condition vehicle\", \"Round trip transportation for Kathmandu- Nagarkot by Private vehicle\", \"Vehicles are not to be disposal and are available as per itinerary only\", \"All current Nepal Government taxes\"]','[\"International Airfare\", \"Insurance Fee\", \"Monuments entrance fees as applicable\", \"Manakamana Cable Car tickets\", \"Boat ride fee on Phewa lake\", \"Personal expenses, tipping and any other services which are not mentioned in the above inclusion.\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrive in Kathmandu\", \"description\": \"Upon arrival in Kathmandu Airport, you will be greeted and assisted by our representative after completing your custom formalities, transfer to the hotel for check-in. And evening attended Aarti at Pashupatinath Temple overnight at Kathmandu hotel.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Kathmandu City Sightseeing\", \"description\": \"After breakfast Kathmandu city sightseeing tour, Jala Narayan Temple (Sleeping Vishnu), Swoyambhunath Stupa (Monkey Temple), Boudhanath Stupa (World heritage site) & Kathmandu Durbar Square (Living God Kumari) drive back to hotel. Overnight is at a hotel in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Kathmandu to Pokhara (6-8 Hours)\", \"description\": \"After breakfast, drive from Kathmandu to Pokhara via the scenic Prithvi highway. On arrival, visit Tal Barahi Temple. Return to the hotel. Evening free for shopping. Overnight in Pokhara.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Sunrise Sarangkot & Pokhara sightseeing\", \"description\": \"Early morning 5AM drive to Pumdikot Temple enjoy with sunrise and Panoramic Mountain View from Pumdikot (Mountain view depends on whether) After That visit to David water falls, Gupteshwor Mahadev Cave, Back to Hotel, take breakfast, later visit to Bindabasini Temple (Durga Temple), Seti River Gorge, and one hour boat ride on Phewa Lake and visit Tal Barahi Temple, later drive back to hotel. Overnight at a hotel in Pokhara.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Pokhara to Kathmandu (6-8 hour)\", \"description\": \"After breakfast, begin your return journey from Pokhara to Kathmandu by road, a scenic drive of around 6-8 hours along the Prithvi Highway. The route passes through charming towns like Damauli Mugling and Kurintar, with views of rivers, hills, and rural life along the way. You can stop for lunch or short breaks at local roadside restaurants. Arrive in Kathmandu by late afternoon or evening and transfer to your hotel.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Sightseeing drive to Nagarkot (About 26 km, 1& half hours’ Drive)\", \"description\": \"After having a leisurely breakfast drive to visit Bhaktapur Durbar Square (World heritage site), Doleshwar Mahadev (Head of Kedarnath Temple) & Kailashnath Mahadev (103 ft. statue of lord Shiva) later drive to Nagarkot upon arrival in Nagarkot transfer to hotel for check-in. Evening Watch sunset from hotel Room balcony. Overnight in at a Hotel in Nagarkot.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 7, \"meals\": \"Breakfast\", \"title\": \"Nagarkot- departure transfer\", \"description\": \"Early morning enjoy sunrise from room balcony and panoramic Mountain View Subject to Weather Condition later take breakfast, after breakfast the morning will be comparatively free and closer to the time of your flight, you will be transferred to airport in time to board your flight for onward journey.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Nagarkot\", \"Kathmandu\", \"Pokhara\"]','[\"Cultural Tours\", \"Volunteering\"]',NULL,NULL,NULL,0,1,'2025-12-28 05:41:05','2025-12-28 05:41:05'),(3,330,'9-day-ultimate-annapurna-sunrise-trek-ghorepani-poon-hill-beyond','9-Day Ultimate Annapurna Sunrise Trek: Ghorepani Poon Hill & Beyond','','','The Essence of Himalayan Trekking Embark on a transformative journey through the heart of the Annapurna region with our signature nine-day Poon Hill expedition. This carefully curated package is designed for those who wish to \"embrace the journey\" by diving deep into the natural and cultural wonders of Nepal. Surpassing even the most thrilling imaginations, this trek offers a seamless blend of physical adventure and spiritual serenity, ensuring that every traveler experiences the true majesty of the Himalayas with the comfort and elegance that defines our service.\n\nA Spectacle of Light and Peak Views The definitive highlight of this adventure is the pre-dawn ascent to the world-famous Poon Hill viewpoint. Standing at an elevation of 3,210 meters, you will witness a breathtaking 360-degree panorama as the morning sun paints the snow-capped summits of the Dhaulagiri and Annapurna massifs in shades of gold and amber. This iconic sunrise experience fulfills every visitor\'s dream, offering a front-row seat to some of the highest peaks on Earth, including the uniquely shaped Machhapuchhre, also known as the \"Fishtail\" mountain.\n\nCultural Immersion in the Annapurna Heartland As you traverse the winding trails, you will encounter the inquisitive diversity of the local Gurung and Magar communities. The journey leads you through vibrant rhododendron forests that bloom with color and past ancient stone villages where traditional mountain life remains beautifully preserved. Much like the dynamic energy of our city tours, the trekking trails offer a constant shift in scenery—from lush subtropical lowlands to the crisp, thin air of the high-altitude ridges. Each evening, you will find sanctuary in handpicked teahouses, allowing you to relax and recover from your travel blues while enjoying authentic local hospitality .\n\nSeamless Logistics and Expert Guidance Your safety and satisfaction are our primary objectives, which is why this trek is fully escorted by a professional English-speaking guide who shares the history and secrets of the mountains. We handle all necessary government taxes, service charges, and ground transfers so that you can focus entirely on the trail ahead. This nine-day itinerary is specifically paced to allow for optimal acclimatization, making it an ideal choice for first-time trekkers or families looking for a rewarding Himalayan escape.\n\nImportant Booking Information To begin this incredible journey, please ensure your passport has at least seven months of validity. Consistent with our standard booking policy, a fifty percent down payment is required upon confirmation to secure your space, with the remaining balance due ten days prior to your departure date. Join us to conquer the trails and witness the legendary Annapurna sunrise on a trek that promises to be the highlight of your travel history.',0.00,NULL,1,0,NULL,'9 days',NULL,'','',0.00,0,'March, April, May, September, October, November','/uploads/tours/9-day-ultimate-annapurna-sunrise-trek-ghorepani-poon-hill-beyond/tour_1769768895114.jpeg','[\"/uploads/tours/9-day-ultimate-annapurna-sunrise-trek-ghorepani-poon-hill-beyond/tour_1769769698504.jpg\"]','[\"Poon Hill Sunrise: Witness a legendary 360-degree sunrise view over the Dhaulagiri and Annapurna mountain ranges.\", \"Ghandruk Village: Explore one of Nepal’s most famous Gurung cultural landmarks and traditional stone-built settlements.\", \"Rhododendron Forests: Trek through vibrant, blooming forests within the world-renowned Annapurna Conservation Area.\", \"Lakeside Pokhara: Enjoy a peaceful retreat in Nepal’s premier lakeside city before and after your trek.\", \"Mountain Panorama: Capture stunning up-close views of Machhapuchhre (Fishtail), Annapurna South, and Hiunchuli.\", \"Teahouse Experience: Stay in handpicked traditional mountain lodges to experience authentic Himalayan hospitality.\", \"Professional Escort: Led by expert English-speaking guides to ensure maximum safety and local insight.\"]','[]','[]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival in Kathmandu\", \"description\": \"Welcome to Nepal’s capital at 1,400m. You will be transferred to your hotel for rest and a trek briefing.\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast \", \"title\": \"Travel to Pokhara\", \"description\": \"Enjoy a scenic 7–9 hour drive to the lakeside city of Pokhara. Spend the evening relaxing by Phewa Lake.\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Drive to Birethanti & Trek to Ulleri\", \"description\": \"Travel to Birethanti and begin your trek with a 4–5 hour climb to the village of Ulleri (2,020m).\", \"accommodation\": \"Guest House \"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Trek to Ghorepani\", \"description\": \"Hike for 5–6 hours through dense rhododendron forests to reach the vibrant mountain village of Ghorepani at 2,810m.\", \"accommodation\": \"Guest House \"}, {\"day\": 5, \"meals\": \"Breakfast \", \"title\": \"Poon Hill Sunrise & Trek to Tadapani\", \"description\": \"Hike to Poon Hill (3,210m) for a 360-degree Himalayan sunrise before trekking 6–7 hours to Tadapani.\", \"accommodation\": \"Guest House\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Trek to Ghandruk Village\", \"description\": \"Enjoy a 4–5 hour descent to Ghandruk (1,940m), a major cultural hub of the Gurung community with stunning peak views.\", \"accommodation\": \"Guest House \"}, {\"day\": 7, \"meals\": \"Breakfast\", \"title\": \"Trek to Nayapul & Return to Pokhara\", \"description\": \"Complete your trek with a walk to Syauli Bazaar and a drive back to Pokhara for a well-deserved evening of rest.\", \"accommodation\": \"3 star Hotel \"}, {\"day\": 8, \"meals\": \"Breakfast\", \"title\": \"Pokhara to Kathmandu\", \"description\": \"Travel back to Kathmandu via a scenic 7–9 hour drive and check into your hotel for your final night in Nepal.\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 9, \"meals\": \"Breakfast\", \"title\": \"Final Departure\", \"description\": \"Transfer to the International Airport for your flight home, carrying unforgettable memories of the Annapurna range.\", \"accommodation\": \"N/A\"}]','\"\"','[\"9-Day Ultimate Annapurna Sunrise Trek: Ghorepani Poon Hill & Beyond\"]','[\"Mountaineering\", \"Adventure Sports\", \"Cultural Tours\"]',NULL,NULL,NULL,0,1,'2026-01-30 10:32:46','2026-01-30 10:41:42'),(4,312,'annapurna-base-camp-trek-12-nights-13-days','Annapurna Base Camp Trek - 12 Nights 13 Days','Trekking','Nepal','Embark on one of Nepal\'s most spectacular trekking adventures to Annapurna Base Camp, situated in the heart of the Annapurna Sanctuary. This incredible journey takes you through diverse landscapes from subtropical forests to alpine meadows, culminating at the base camp surrounded by towering peaks including Annapurna I (8,091m), Machapuchare (6,993m), and Hiunchuli (6,441m). Experience the rich culture of Gurung and Magar communities, soak in natural hot springs, and witness breathtaking sunrise views over the Annapurna massif.',0.00,NULL,0,0,NULL,'13 days',NULL,'2-12 people','Moderate to Challenging',4.80,234,'March-May, September-November','','[\"https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Reach Annapurna Base Camp at 4,130m\", \"360-degree mountain views in the sanctuary\", \"Natural hot springs at Jhinu Danda\", \"Diverse flora and fauna\", \"Gurung and Magar cultural experience\", \"Spectacular sunrise over Annapurna massif\", \"Rhododendron forests in spring\"]','[\"Teahouse accommodation during trek\", \"All meals during trekking\", \"Professional trekking guide\", \"Porter service (1 porter for 2 trekkers)\", \"All permits and fees (ACAP, TIMS)\", \"First aid kit and oxygen meter\", \"Transportation (Kathmandu-Pokhara-Kathmandu)\", \"Airport transfers\"]','[\"International flights\", \"Nepal visa fees\", \"Meals in Kathmandu and Pokhara\", \"Personal trekking equipment\", \"Travel insurance\", \"Emergency evacuation\", \"Tips for guide and porters\", \"Personal expenses and drinks\"]','[{\"name\": \"High Altitude Trekking\", \"description\": \"Trek through diverse ecosystems from tropical to alpine zones\"}, {\"name\": \"Cultural Immersion\", \"description\": \"Experience Gurung and Magar village life and traditions\"}, {\"name\": \"Natural Hot Springs\", \"description\": \"Relax in therapeutic hot springs at Jhinu Danda\"}, {\"name\": \"Wildlife Observation\", \"description\": \"Spot Himalayan wildlife in the Annapurna Conservation Area\"}]','[{\"day\": 1, \"title\": \"Arrival in Kathmandu (1,400m)sssss\", \"description\": \"Welcome to Nepal! Upon arrival at Tribhuvan International Airport, our representative will meet you and transfer you to your hotel in Kathmandu. After check-in, attend a comprehensive pre-trek briefing where you\'ll meet your trekking guide and receive detailed information about the Annapurna Base Camp trek. Equipment check and final preparations. Evening welcome dinner featuring traditional Nepali cuisine and cultural performances. Overnight in Kathmandu.\"}, {\"day\": 2, \"title\": \"Drive to Pokhara (822m)\", \"description\": \"After breakfast, embark on a scenic 6-7 hour drive to Pokhara through winding mountain roads, terraced fields, and traditional villages. The journey offers glimpses of rural Nepali life and changing landscapes. Alternatively, take a 25-minute domestic flight for spectacular aerial views of the Himalayas. Upon arrival in Pokhara, check into lakeside hotel and enjoy the serene atmosphere of Phewa Lake. Evening free to explore the vibrant Lakeside area with its restaurants, cafes, and shops. Final trek preparations and equipment check.\"}, {\"day\": 3, \"title\": \"Drive to Nayapul & Trek to Tikhedhunga (1,577m)\", \"description\": \"Early morning drive to Nayapul (1,070m), the starting point of your Annapurna Base Camp trek. Begin trekking along the Modi Khola river through beautiful countryside and traditional villages. Cross suspension bridges and pass through Birethanti, where you\'ll complete permit formalities. The trail gradually ascends through terraced fields and small settlements. Arrive at Tikhedhunga, a small village with teahouses offering basic but comfortable accommodation. Trek duration: 4-5 hours. Overnight in teahouse.\"}, {\"day\": 4, \"title\": \"Trek to Ghorepani (2,874m)\", \"description\": \"Today involves a challenging climb up the famous stone steps to Ulleri village, followed by a gradual ascent through beautiful rhododendron and oak forests. The trail offers occasional glimpses of Annapurna South and Hiunchuli peaks. Pass through several small villages and experience the hospitality of local Magar and Gurung communities. Arrive at Ghorepani, a popular trekking hub with stunning mountain views. The village name means \'horse water,\' reflecting its historical importance as a trading route. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 5, \"title\": \"Poon Hill Sunrise & Trek to Tadapani (2,630m)\", \"description\": \"Pre-dawn hike to Poon Hill (3,210m), one of the most famous viewpoints in the Himalayas. Watch the spectacular sunrise illuminate the Annapurna and Dhaulagiri mountain ranges, including Annapurna I, Annapurna South, Machapuchare, Dhaulagiri, and many other peaks. The panoramic 360-degree views are absolutely breathtaking. Return to Ghorepani for breakfast, then continue trekking through dense rhododendron forests (spectacular in spring) to Tadapani. The trail offers beautiful mountain views and diverse flora. Trek duration: 6-7 hours including Poon Hill. Overnight in teahouse.\"}, {\"day\": 6, \"title\": \"Trek to Sinuwa (2,360m)\", \"description\": \"Descend through beautiful forests with occasional clearings offering mountain views. The trail passes through Banthanti and continues through dense rhododendron and bamboo forests. Cross several streams and enjoy the changing vegetation as you descend. The path can be muddy and slippery during monsoon season, requiring careful footing. Arrive at Sinuwa, a small settlement with basic teahouse facilities. The village offers good views of Machapuchare and Annapurna South. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 7, \"title\": \"Trek to Deurali (3,230m)\", \"description\": \"Continue ascending through the Modi Khola valley with increasingly spectacular mountain views. Pass through Chhomrong, a large Gurung village with excellent mountain views and the last permanent settlement before entering the Annapurna Sanctuary. Cross the Chhomrong Khola on a suspension bridge and climb steeply up stone steps. The trail then descends to Bamboo and continues through dense bamboo and rhododendron forests to Deurali. The landscape becomes more alpine as you gain altitude. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 8, \"title\": \"Trek to Annapurna Base Camp (4,130m)\", \"description\": \"The ultimate day! Early start for the final push to Annapurna Base Camp. Pass through Machapuchare Base Camp (3,700m) with stunning close-up views of the sacred Machapuchare peak. Continue ascending through the glacial valley into the heart of the Annapurna Sanctuary. The landscape becomes increasingly dramatic with towering peaks surrounding you on all sides. Reach Annapurna Base Camp, situated in a natural amphitheater surrounded by some of the world\'s highest peaks. Celebrate this incredible achievement and take in the surreal 360-degree mountain panorama. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 9, \"title\": \"Sunrise at ABC & Trek to Bamboo (2,310m)\", \"description\": \"Wake up early to witness one of the world\'s most spectacular sunrises as the first rays of light illuminate the surrounding peaks including Annapurna I, Annapurna South, Machapuchare, Hiunchuli, and Gangapurna. The golden glow on the snow-capped peaks is absolutely magical. After breakfast and final photos, begin the descent retracing your steps through Machapuchare Base Camp and Deurali to Bamboo. The long descent requires careful attention to footing. Trek duration: 7-8 hours. Overnight in teahouse.\"}, {\"day\": 10, \"title\": \"Trek to Jhinu Danda (1,780m)\", \"description\": \"Continue descending through the Modi Khola valley, passing through Sinuwa and Chhomrong. The trail offers different perspectives of the mountains you\'ve just visited. Arrive at Jhinu Danda, famous for its natural hot springs. After checking into the teahouse, take a 20-minute walk down to the hot springs located beside the Modi Khola river. Soak your tired muscles in the therapeutic hot water while enjoying views of the surrounding hills. This is a perfect way to relax after days of challenging trekking. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 11, \"title\": \"Trek to Nayapul & Drive to Pokhara\", \"description\": \"Final trekking day descending through familiar territory with a sense of accomplishment. Pass through traditional villages, terraced fields, and cross suspension bridges over rushing rivers. Reflect on your incredible journey and the memories created in the Annapurna Sanctuary. Arrive at Nayapul where your trek officially ends. Drive back to Pokhara and check into your lakeside hotel. Celebrate your successful Annapurna Base Camp trek with your team. Evening free for shopping, spa treatments, or simply relaxing by Phewa Lake. Trek duration: 5-6 hours. Overnight in Pokhara.\"}, {\"day\": 12, \"title\": \"Return to Kathmandu\", \"description\": \"Morning flight or drive back to Kathmandu depending on your preference and weather conditions. The flight offers spectacular aerial views of the mountains you\'ve just trekked to, providing a different perspective of your achievement. Upon arrival in Kathmandu, transfer to your hotel and enjoy a hot shower and comfortable bed. Afternoon free for shopping in Thamel, spa treatments, or exploring additional sights in Kathmandu. Evening celebration dinner with cultural show featuring traditional Nepali music and dance. Receive your trek completion certificate. Overnight in Kathmandu.\"}, {\"day\": 13, \"title\": \"Departure\", \"description\": \"Final day in Nepal. Depending on your flight schedule, enjoy some last-minute shopping in Thamel for trekking gear, handicrafts, or souvenirs. Visit additional sights in Kathmandu if time permits. Our representative will assist with airport transfer according to your flight schedule. Depart with incredible memories of your Annapurna Base Camp adventure, the stunning mountain views, cultural experiences, and a tremendous sense of personal achievement that will last a lifetime.\"}]','\"Good physical fitness required. Regular cardio training and hiking experience recommended. Ability to walk 6-8 hours daily on varied terrain.\"','[\"Annapurna \"]','[\"Adventure Sports\", \"Mountaineering\"]',NULL,NULL,NULL,1,1,'2024-12-30 10:00:00','2025-12-18 21:06:46'),(5,322,'discover-chinas-spirit-in-beijing-shanghai','Discover China’s Spirit in Beijing & Shanghai','','','Discover the dynamic spirit of China with an unforgettable journey through Beijing, Shanghai, and Chengdu. From Beijing’s majestic imperial landmarks and rich cultural heritage to Shanghai’s dazzling skyline and modern cosmopolitan energy, and finally to Chengdu’s laid-back charm and world-famous giant pandas, this tour blends history, innovation, and natural beauty. Experience the essence of China— past, present, and future—across three of its most captivating cities.',0.00,NULL,1,0,NULL,'6 days',NULL,'2-8','',0.00,0,'','/uploads/tours/discover-chinas-spirit-in-beijing-shanghai/tour_1766465732623.jpg','[\"/uploads/tours/discover-chinas-spirit-in-beijing-shanghai/tour_1766465741121.jpg\", \"/uploads/tours/discover-chinas-spirit-in-beijing-shanghai/tour_1766465741239.webp\", \"/uploads/tours/discover-chinas-spirit-in-beijing-shanghai/tour_1766465741407.avif\"]','[\"Explore historic Beijing: Tiananmen Square, Forbidden City & Temple of Heaven\", \"Walk on the Great Wall of China at Juyong Pass\", \"Photo stop at the Bird’s Nest Stadium\", \"Travel by high-speed bullet train to Shanghai\", \"Discover Shanghai’s top sights: Jade Buddha Temple, Yu Garden, The Bund\", \"Enjoy shopping & nightlife at Xintiandi and Nanjing Road\"]','[\"Accommodation in well-appointed hotels on a twin/double sharing basis\", \"Daily breakfast at hotels as mentioned in the itinerary\", \"Airport transfers on arrival and departure in Beijing and Shanghai\", \"All inter-city transfers and sightseeing by comfortable air-conditioned vehicle\", \"High-speed bullet train ticket from Beijing to Shanghai (standard class)\", \"Guided city tours in Beijing and Shanghai as per itinerary\", \"Shopping visit to local markets and Yu Garden Bazaar\", \"Professional English-speaking local guide during sightseeing tours\", \"All applicable local taxes and service charges\", \"Round trip International airfare \", \"China visa fees\"]','[\"Travel insurance (strongly recommended)\", \"Lunches and dinners unless specifically mentioned\", \"Personal expenses such as laundry, telephone calls, minibar, tips, porterage, etc.\", \"Optional tours and activities not mentioned in the itinerary\", \"Camera/video fees at monuments (if applicable)\", \"Early check-in or late check-out at hotels (subject to availability)\", \"Any increase in taxes, fuel surcharge, or train fare after booking confirmation\", \"Expenses due to unforeseen circumstances such as flight delays, natural disasters, strikes, or government restrictions\", \"Anything not clearly mentioned under the “Tour Inclusions” section\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival in Beijing Airport | Transfer to Hotel\", \"description\": \"Upon arrival at Beijing Airport, you will be warmly welcomed and transferred to hotel. After check-in, enjoy some leisure time to rest or explore the nearby surrounding area at your own pace.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Beijing City Tour (Tiananmen Square, Forbidden City, Temple of Heaven)\", \"description\": \"After breakfast, start with a visit to Tiananmen Square, the heart of Beijing and one of the largest public squares in the world. From there, walk into the grand Forbidden City (Palace Museum), the spectacular imperial palace that was home to China’s emperors for over 500 years. Later, visit the Temple of Heaven, a masterpiece of Ming and Qing architecture where emperors once performed solemn rituals to pray for good harvests, offering a tranquil contrast to the bustling city.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Great wall of China | Outside View of bird nest\", \"description\": \"After breakfast, set out to visit one of the world’s greatest wonders; the Great Wall at Juyong Pass. Stroll along the ancient ramparts, capture stunning photos, and admire the breathtaking mountain scenery. On your return journey, make a brief stop for an outside view of the Bird’s Nest (Beijing National Stadium), the architectural marvel of the 2008 Olympics. In the afternoon, browse a local market to enjoy some shopping and local interactions.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Beijing to Shanghai by High-speed Bullet Train\", \"description\": \"After breakfast, check out and transfer to the station to board a high-speed bullet train to Beijing, offering a scenic and comfortable ride through the Chinese countryside. Upon arrival in Beijing, transfer to your hotel. Spend the rest of the day at leisure, settling in and preparing for your exploration of the Capital.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Shanghai Highlights (Jade Buddha Temple, Yu Market, The Bund, Xintiandi, Nanjing Road) \", \"description\": \"After breakfast, begin your Shanghai city tour with a visit to the peaceful Jade Buddha Temple, famous for its exquisite jade Buddha statues. Continue to the Yu Garden Bazaar, a lively marketplace surrounded by traditional architecture where you can shop for souvenirs and local snacks. Later, stroll along The Bund, Shanghai’s iconic waterfront, renowned for its colonial-era buildings and spectacular skyline views across the Huangpu River. In the evening, explore. Xintiandi, a stylish district blending old Shikumen houses with trendy restaurants and boutiques. Finally, enjoy a walk down the bustling Nanjing Road, Shanghai’s premier shopping avenue, before returning to your hotel.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Departure\", \"description\": \"After breakfast you will be transfer to Airport according to your flight time.\", \"accommodation\": \"3-Star Hotel\"}]','\"\"','[\"China\"]','[\"Luxury Experiences\", \"Cultural Tours\", \"City Tours\"]',NULL,NULL,NULL,0,1,'2025-12-23 04:55:48','2025-12-23 04:56:57'),(6,201,'dubai-city-explorer-4-days','Dubai City Explorer - 4 Days','Cultural','Dubai, UAE','Discover the modern marvels and traditional charm of Dubai in this comprehensive 4-day city tour. Experience iconic landmarks, luxury shopping, and authentic Emirati culture.',0.00,NULL,0,0,NULL,'4 days',NULL,'2-15 people','Easy',4.80,156,'November-March','https://images.unsplash.com/photo-1512453979798-5ea266f8880c?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1512453979798-5ea266f8880c?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1518684079-3c830dcef090?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1582672060674-bc2bd808a8b5?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Burj Khalifa observation deck visit\", \"Dubai Mall shopping experience\", \"Traditional Gold and Spice Souks\", \"Dubai Marina cruise\", \"Old Dubai heritage tour\", \"Dubai Fountain show\", \"Palm Jumeirah monorail ride\", \"Atlantis Resort visit\"]','[\"4-star hotel accommodation (3 nights)\", \"Daily breakfast\", \"Airport transfers\", \"All entrance fees\", \"Professional English-speaking guide\", \"Air-conditioned transportation\", \"Dubai Marina cruise\", \"Burj Khalifa tickets\"]','[\"International flights\", \"Lunch and dinner\", \"Personal expenses\", \"Travel insurance\", \"Tips for guide and driver\", \"Optional activities\", \"Visa fees\"]','[{\"name\": \"Burj Khalifa Experience\", \"description\": \"Visit the world\'s tallest building and enjoy panoramic views from the observation deck\"}, {\"name\": \"Traditional Souks\", \"description\": \"Explore the historic Gold Souk and Spice Souk in old Dubai\"}, {\"name\": \"Dubai Marina Cruise\", \"description\": \"Scenic boat cruise through Dubai\'s modern marina district\"}, {\"name\": \"Cultural Heritage\", \"description\": \"Discover Dubai\'s history at Al Fahidi Historical District\"}]','[{\"day\": 1, \"meals\": \"Breakfast\", \"title\": \"Arrival & Modern Dubai\", \"description\": \"Airport pickup and transfer to hotel. Check-in and rest. Afternoon visit to Burj Khalifa observation deck. Evening at Dubai Mall with dinner and Dubai Fountain show.\", \"accommodation\": \"4-star hotel in Dubai\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Traditional Dubai Heritage\", \"description\": \"Morning visit to Dubai Creek area. Explore Gold Souk and Spice Souk. Visit Al Fahidi Historical District and Dubai Museum. Traditional lunch. Afternoon abra ride across Dubai Creek.\", \"accommodation\": \"4-star hotel in Dubai\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Dubai Marina & Palm Jumeirah\", \"description\": \"Morning at Dubai Marina with walking tour. Marina cruise experience. Visit Palm Jumeirah and Atlantis Resort. Monorail ride. Evening at JBR Beach and The Walk.\", \"accommodation\": \"4-star hotel in Dubai\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Last-minute Shopping & Departure\", \"description\": \"Final shopping at Dubai Mall or Mall of the Emirates. Check-out from hotel. Airport transfer for departure.\", \"accommodation\": \"End of tour\"}]','\"Basic fitness level sufficient. Involves moderate walking. Suitable for all ages.\"','[\"Dubai\"]','[\"Luxury Experiences\", \"City Tours\", \"Desert Safari\"]',NULL,NULL,NULL,1,1,'2025-01-20 15:38:00','2025-12-18 05:03:45'),(7,202,'dubai-desert-adventure-3-days','Dubai Desert Adventure - 3 Days','Adventure','Dubai Desert, UAE','Experience the thrill of the Arabian Desert with dune bashing, camel riding, and traditional Bedouin camp experiences. Perfect for adventure seekers looking for authentic desert culture.',649.00,NULL,0,0,NULL,'3 days',NULL,'4-12 people','Moderate',4.70,203,'October-April','https://images.unsplash.com/photo-1451337516015-6b6e9a44a8a3?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1451337516015-6b6e9a44a8a3?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1539650116574-75c0c6d73f6e?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"4WD dune bashing adventure\", \"Camel trekking experience\", \"Traditional Bedouin camp overnight\", \"Sandboarding activities\", \"Falconry demonstration\", \"Arabian BBQ dinner under stars\", \"Traditional henna painting\", \"Desert sunrise photography\"]','[\"Desert camp accommodation (2 nights)\", \"All meals during desert stay\", \"4WD transportation\", \"All desert activities\", \"Professional desert guide\", \"Traditional entertainment\", \"Camel riding\", \"Sandboarding equipment\"]','[\"Dubai hotel accommodation\", \"International flights\", \"Personal expenses\", \"Travel insurance\", \"Alcoholic beverages\", \"Tips for guide and driver\", \"City transfers (if not staying in Dubai)\"]','[{\"name\": \"Dune Bashing\", \"description\": \"Thrilling 4WD ride over sand dunes with experienced drivers\"}, {\"name\": \"Camel Trekking\", \"description\": \"Traditional camel rides through the desert landscape\"}, {\"name\": \"Bedouin Camp Experience\", \"description\": \"Overnight stay in traditional desert camp with cultural activities\"}, {\"name\": \"Sandboarding\", \"description\": \"Surf the sand dunes on specially designed boards\"}]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Desert Safari & Camp Setup\", \"description\": \"Pickup from Dubai in the afternoon. Drive to desert location. Thrilling dune bashing session. Camel ride at sunset. Arrive at Bedouin camp. Traditional welcome with Arabic coffee and dates. BBQ dinner with live entertainment including belly dancing and fire shows.\", \"accommodation\": \"Traditional Bedouin camp\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Desert Activities & Culture\", \"description\": \"Early morning sunrise photography session. Traditional breakfast. Sandboarding activities. Falconry demonstration. Learn about desert survival techniques. Henna painting session. Traditional lunch. Afternoon rest. Evening cultural programs and stargazing.\", \"accommodation\": \"Traditional Bedouin camp\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Morning Desert Walk & Return\", \"description\": \"Early morning desert walk and bird watching. Final breakfast in the desert. Pack up camp. Scenic drive back to Dubai with photo stops. Drop-off at Dubai location.\", \"accommodation\": \"End of tour\"}]','\"Moderate fitness required for sandboarding and camel riding. Some activities may not be suitable for pregnant women or people with back problems.\"','[\"Dubai\"]','[\"Desert Safari\"]',NULL,NULL,NULL,1,1,'2025-01-20 15:38:00','2025-09-20 19:40:45'),(8,203,'dubai-luxury-experience-5-days','Dubai Luxury Experience - 5 Days','Luxury','Dubai, UAE','Indulge in the ultimate Dubai luxury experience with 5-star accommodations, private tours, fine dining, and exclusive access to premium attractions. Perfect for those seeking the finest Dubai has to offer.',0.00,NULL,0,1,10.00,'5 days',NULL,'2-8 people','Easy',4.90,87,'November-March','https://images.unsplash.com/photo-1582672060674-bc2bd808a8b5?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1582672060674-bc2bd808a8b5?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1566073771259-6a8506099945?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1571896349842-33c89424de2d?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"5-star luxury hotel accommodation\", \"Private helicopter tour over Dubai\", \"Atlantis Resort VIP day pass\", \"Private yacht charter experience\", \"Fine dining at Michelin-starred restaurants\", \"VIP shopping assistance\", \"Luxury spa treatments included\", \"Private desert safari with exclusive camp\"]','[\"5-star luxury hotel (4 nights)\", \"All meals at premium restaurants\", \"Private luxury transportation\", \"All premium experiences and activities\", \"Personal concierge service\", \"Spa treatments (2 sessions)\", \"Private helicopter tour\", \"Private yacht charter (4 hours)\", \"VIP shopping assistance\"]','[\"International flights\", \"Personal shopping purchases\", \"Additional spa services\", \"Travel insurance\", \"Alcoholic beverages (unless specified)\", \"Tips for staff\", \"Visa fees\"]','[{\"name\": \"Private Helicopter Tour\", \"description\": \"Exclusive aerial tour of Dubai\'s iconic landmarks and coastline\"}, {\"name\": \"Luxury Yacht Charter\", \"description\": \"Private yacht experience with gourmet dining and water activities\"}, {\"name\": \"VIP Atlantis Experience\", \"description\": \"Exclusive access to Atlantis Resort facilities and attractions\"}, {\"name\": \"Fine Dining Experience\", \"description\": \"Curated dining experiences at Dubai\'s most prestigious restaurants\"}]','[{\"day\": 1, \"meals\": \"Welcome dinner\", \"title\": \"Luxury Arrival & Welcome\", \"description\": \"VIP airport pickup in luxury vehicle. Check-in at 5-star hotel with suite upgrade. Welcome spa treatment. Evening welcome dinner at Burj Al Arab\'s Al Muntaha restaurant with panoramic city views.\", \"accommodation\": \"5-star luxury hotel suite\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Sky High Dubai Experience\", \"description\": \"Private helicopter tour over Dubai\'s iconic landmarks. VIP access to Burj Khalifa with private guide. Luxury shopping experience at Dubai Mall with personal shopping assistant. Afternoon at luxury spa. Evening fine dining at Nobu Dubai.\", \"accommodation\": \"5-star luxury hotel suite\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Atlantis VIP Experience\", \"description\": \"Private transfer to Atlantis Resort. VIP day pass including Lost Chambers Aquarium, Aquaventure Waterpark, and Dolphin Bay experience. Luxury spa treatment at ShuiQi Spa. Evening dinner at Ossiano underwater restaurant.\", \"accommodation\": \"5-star luxury hotel suite\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Private Yacht & Desert Luxury\", \"description\": \"Morning private yacht charter (4 hours) with gourmet lunch onboard. Water activities and relaxation. Afternoon return to hotel. Evening luxury desert safari with private camp, gourmet dinner, and exclusive entertainment.\", \"accommodation\": \"5-star luxury hotel suite\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch\", \"title\": \"Final Luxury & Departure\", \"description\": \"Final spa treatment and relaxation. Last-minute luxury shopping with VIP assistance. Private farewell lunch at At.mosphere restaurant in Burj Khalifa. VIP airport transfer in luxury vehicle.\", \"accommodation\": \"End of tour\"}]','\"No specific fitness requirements. All activities are designed for comfort and luxury. Suitable for all ages.\"','[\"Dubai\"]','[\"Desert Safari\"]',NULL,NULL,NULL,1,1,'2025-01-20 15:39:00','2025-12-18 04:22:18'),(9,308,'everest-base-camp-trek-13n-14d','Everest Base Camp Trek - 13 Nights 14 Days','Trekking','Nepal','Embark on the ultimate Himalayan adventure to Everest Base Camp, following in the footsteps of legendary mountaineers. This iconic trek takes you through the heart of the Khumbu region, offering breathtaking views of the world\'s highest peaks including Mount Everest, Lhotse, and Ama Dablam. Experience Sherpa culture, visit ancient monasteries, and challenge yourself on this once-in-a-lifetime journey to the base of the world\'s tallest mountain.',0.00,NULL,0,0,NULL,'14 days',NULL,'2-12 people','Challenging',4.90,287,'March-May, September-November','https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Reach Everest Base Camp at 5,364m\", \"Spectacular mountain views from Kala Patthar\", \"Experience authentic Sherpa culture\", \"Visit Tengboche Monastery\", \"Cross suspension bridges over deep gorges\", \"Explore Sagarmatha National Park\", \"Witness sunrise over Mount Everest\"]','[\"Domestic flights (Kathmandu-Lukla-Kathmandu)\", \"Teahouse accommodation during trek\", \"All meals during trekking\", \"Professional trekking guide\", \"Porter service (1 porter for 2 trekkers)\", \"All permits and fees\", \"First aid kit and oxygen meter\", \"Airport transfers\"]','[\"International flights\", \"Nepal visa fees\", \"Meals in Kathmandu\", \"Personal trekking equipment\", \"Travel insurance\", \"Emergency evacuation\", \"Tips for guide and porters\", \"Personal expenses\"]','[{\"name\": \"High Altitude Trekking\", \"description\": \"Trek through diverse landscapes from subtropical forests to alpine terrain\"}, {\"name\": \"Cultural Immersion\", \"description\": \"Experience Sherpa culture and visit Buddhist monasteries\"}, {\"name\": \"Mountain Photography\", \"description\": \"Capture stunning views of world\'s highest peaks\"}, {\"name\": \"Wildlife Viewing\", \"description\": \"Spot Himalayan wildlife in Sagarmatha National Park\"}]','[{\"day\": 1, \"title\": \"Arrival in Kathmandu (1,400m)\", \"description\": \"Welcome to Nepal! Upon arrival at Tribhuvan International Airport, our representative will meet you and transfer you to your hotel in Kathmandu. After check-in, attend a pre-trek briefing where you\'ll meet your trekking guide and receive detailed information about the trek. Equipment check and final preparations. Evening welcome dinner featuring traditional Nepali cuisine. Overnight in Kathmandu.\"}, {\"day\": 2, \"title\": \"Fly to Lukla & Trek to Phakding (2,652m)\", \"description\": \"Early morning flight to Lukla (2,800m), one of the world\'s most thrilling airports. The 35-minute scenic flight offers spectacular mountain views. Upon landing, meet your porter and begin the trek to Phakding. The trail descends through pine forests and crosses several suspension bridges over the Dudh Koshi River. Pass through small Sherpa villages and enjoy your first taste of mountain hospitality. Trek duration: 3-4 hours. Overnight in teahouse.\"}, {\"day\": 3, \"title\": \"Trek to Namche Bazaar (3,440m)\", \"description\": \"Today\'s trek takes you to the famous Namche Bazaar, the gateway to Everest. Cross numerous suspension bridges including the spectacular Hillary Suspension Bridge. Enter Sagarmatha National Park and begin the steep ascent to Namche. The trail offers first glimpses of Mount Everest, Lhotse, and other peaks. Namche Bazaar is a bustling Sherpa town with shops, restaurants, and internet cafes. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 4, \"title\": \"Acclimatization Day in Namche Bazaar\", \"description\": \"Important acclimatization day to help your body adjust to altitude. Optional hike to Everest View Hotel (3,880m) for spectacular mountain panoramas including Mount Everest, Ama Dablam, and Lhotse. Visit the Sherpa Culture Museum and learn about mountaineering history. Explore Namche\'s colorful Saturday market (if timing permits). Alternative hike to Khumjung village to visit Hillary School and monastery. Rest and prepare for higher altitudes ahead.\"}, {\"day\": 5, \"title\": \"Trek to Tengboche (3,867m)\", \"description\": \"Descend from Namche and cross the Dudh Koshi River. The trail contours around the mountainside with stunning views of Ama Dablam, one of the most beautiful peaks in the Himalayas. Gradual ascent through rhododendron forests leads to Tengboche, home to the region\'s largest monastery. Visit Tengboche Monastery and witness evening prayers if timing permits. Spectacular 360-degree mountain views including Everest, Nuptse, and Lhotse. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 6, \"title\": \"Trek to Dingboche (4,410m)\", \"description\": \"Descend through forests to Debuche and cross the Imja River. The trail gradually ascends through alpine meadows with incredible mountain views. Pass through Pangboche village, one of the highest permanent settlements in the world. Continue ascending to Dingboche, a summer settlement with stone-walled fields. The landscape becomes more barren and alpine. Spectacular views of Island Peak, Lhotse, and Ama Dablam. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 7, \"title\": \"Acclimatization Day in Dingboche\", \"description\": \"Another crucial acclimatization day. Optional hike to Nagarjun Hill (5,083m) for panoramic views of Makalu, Lhotse, Chalotse, Tawache, and Ama Dablam. Alternative hike to Chhukung village (4,730m) for closer views of Island Peak and Lhotse South Face. Rest day allows your body to produce more red blood cells and adjust to the thin air. Explore the village and interact with local Sherpa families. Prepare for the challenging days ahead.\"}, {\"day\": 8, \"title\": \"Trek to Lobuche (4,940m)\", \"description\": \"Continue ascending through the alpine desert landscape. Pass the memorial site dedicated to climbers who lost their lives on Everest, including Scott Fischer and others. The trail becomes more challenging as oxygen levels decrease. Cross the terminal moraine of the Khumbu Glacier with views of Pumori and other peaks. Arrive at Lobuche, a small settlement in a dramatic setting surrounded by towering peaks. Trek duration: 5-6 hours. Overnight in teahouse.\"}, {\"day\": 9, \"title\": \"Trek to Everest Base Camp (5,364m) & Return to Gorak Shep (5,164m)\", \"description\": \"The ultimate day! Early start for the trek to Everest Base Camp. Navigate through the Khumbu Glacier\'s rocky moraine with prayer flags marking the way. Reach Everest Base Camp, the staging point for Everest expeditions. Celebrate this incredible achievement with photos and take in the surreal landscape of ice seracs and glacial formations. Return to Gorak Shep for overnight stay. Trek duration: 7-8 hours. This is the highlight of your journey!\"}, {\"day\": 10, \"title\": \"Hike to Kala Patthar (5,545m) & Trek to Pheriche (4,371m)\", \"description\": \"Pre-dawn start for the challenging climb to Kala Patthar, the best viewpoint for Mount Everest. Watch the sunrise illuminate the world\'s highest peak along with Nuptse, Changtse, and Lhotse. The panoramic views are absolutely breathtaking and worth every step of the challenging ascent. Descend to Gorak Shep for breakfast, then continue down to Pheriche. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 11, \"title\": \"Trek to Namche Bazaar (3,440m)\", \"description\": \"Long descent day retracing your steps through Pangboche and Tengboche. Cross the suspension bridge over Dudh Koshi River and ascend back to Namche Bazaar. Enjoy the thicker air and warmer temperatures as you descend. Celebrate your successful Everest Base Camp achievement with fellow trekkers. Last night in the mountains with hot showers and comfortable beds available. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 12, \"title\": \"Trek to Lukla (2,800m)\", \"description\": \"Final trekking day descending through familiar territory. Pass through Phakding and continue to Lukla. Reflect on your incredible journey and the memories created. Celebrate with your trekking team and enjoy a farewell dinner. Pack your bags and prepare for the flight back to Kathmandu tomorrow. Trek duration: 6-7 hours. Overnight in teahouse.\"}, {\"day\": 13, \"title\": \"Fly to Kathmandu\", \"description\": \"Morning flight from Lukla to Kathmandu (weather permitting). Upon arrival, transfer to your hotel and enjoy a hot shower and comfortable bed. Afternoon free for shopping, spa treatments, or exploring Kathmandu. Evening celebration dinner with cultural show featuring traditional Nepali music and dance. Receive your trek completion certificate. Overnight in Kathmandu.\"}, {\"day\": 14, \"title\": \"Departure\", \"description\": \"Final day in Nepal. Depending on your flight schedule, enjoy some last-minute shopping in Thamel or visit additional sights in Kathmandu. Our representative will assist with airport transfer. Depart with incredible memories of your Everest Base Camp adventure and a sense of accomplishment that will last a lifetime.\"}]','\"Excellent physical fitness required. Regular cardio training and hiking experience recommended. Ability to walk 6-8 hours daily on rough terrain.\"','[]','[]',NULL,NULL,NULL,1,1,'2024-12-30 10:00:00','2025-12-18 04:22:29'),(10,321,'experience-the-magic-of-bali','Experience the Magic of Bali','','','Bali, the Indonesian paradise is notoriously known for its active volcanos, aqua blue sea, sandy beaches, rice fields, greeneries, artistic temples and warm Balinese people. Bali is the only island in Indonesia with highest Hindu population. It is located at the westernmost end of the Lesser Sunda Islands, with Java to the west and Lombok to the east. Its capital, Denpasar, is located in the southern part of the island.',0.00,NULL,1,0,NULL,'5 days',NULL,'2-8','',0.00,0,'','/uploads/tours/experience-the-magic-of-bali/tour_1766402809242.jpg','[\"/uploads/tours/experience-the-magic-of-bali/tour_1766403727867.avif\", \"/uploads/tours/experience-the-magic-of-bali/tour_1766403727876.webp\", \"/uploads/tours/experience-the-magic-of-bali/tour_1766403727998.jpg\", \"/uploads/tours/experience-the-magic-of-bali/tour_1766403728031.jpg\"]','[\"Airport transfers\", \"Hotel stay\", \"Denpasar City Tour\", \"Ubud & Ubud Market\", \"Celuk Silver Village\", \"Tanah Lot Temple\", \"Uluwatu Temple\", \"Sunset views\", \"Jimbaran seafood dinner\"]','[\"Private airport transfers \", \"Hotel accommodation\", \"Guided sightseeing tours as per itinerary\", \"Visits to Denpasar, Ubud & Celuk Village\", \"Tanah Lot & Uluwatu Temple experiences with sunsets\", \"Jimbaran Bay seafood dinner\", \"Entrance fees, local taxes & on-ground assistance\", \"International Flight\", \"Indonesia Visa Fee\"]','[\"Travel insurance, medical insurance, and personal accident coverage\", \"Early check-in or late check-out at hotels (subject to availability)\", \"Personal expenses such as laundry, telephone calls, minibar, spa treatments, room service, and shopping\", \"Meals and beverages not specifically mentioned in the tour inclusions\", \"Optional tours, activities, adventure sports, or experiences not listed in the itinerary\", \"Tips, gratuities, and porterage for drivers, guides, and hotel staff\", \"Any increase in government taxes, fuel surcharges, or entrance fees imposed after booking\", \"Expenses arising due to unforeseen circumstances such as flight delays, cancellations, natural calamities, strikes, or political disturbances\", \"Additional sightseeing or transfers not mentioned in the itinerary\", \"Any services, items, or costs not expressly mentioned under “Tour Inclusions”\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival at the Airport & Free Day\", \"description\": \"Upon arrival at Bali Airport, you will be warmly welcomed and transferred to your hotel in a private vehicle. After check-in, take time to relax and unwind after your journey. You may explore nearby streets, enjoy the local ambiance, or simply rest in your comfortable hotel. This day is designed to help you acclimatize and prepare for the exciting Bali experiences ahead. Overnight stay at the hotel.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Denpasar City Tour & Ubud Exploration\", \"description\": \"After breakfast, start with Bajra Sandi Monument, honoring Balinese history. Explore the Bali Museum, home to artefacts, paintings, bronze-age weapons, and musical instruments. Visit Celuk Village, renowned for silver and gold handicrafts, and witness artisans at work. Continue to Ubud, the cultural heart of Bali, and explore Ubud Market, filled with local crafts, textiles, and souvenirs. Return to the hotel for an overnight stay.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Tanah LotTemple, Uluwatu & Jimbaran Bay with Seafood Dinner\", \"description\": \"Uluwatu temple: Built on the top of a cliff about 825 feet high facing the vast deep blue Indian Ocean also offers a wonderful view of the sunset. You will also meet lots of monkeys here. The view of ocean from Uluwatu is just enchanting.\\nTanah Lot: A spectacular temple built in the 17th century, on top of rock about 200 meters offshore. The whole compound will turn into a wonderful silhouette as the sunset right behind the temple, one of the most photographed temples on the island - for good reason. The perfect combo of rustling of the waves, the sun and the temple leaves you with positive energy. You can also buy souvenirs here, they have varieties of Balinese crafts, linen and arts.\\nJimbaran Bay with Sea Food: In the evening, proceed to Jimbaran Bay for a delightful seafood dinner with a beautiful ocean view. Return to your hotel for an overnight stay.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Free Day for Leisure & Exploration\", \"description\": \"Enjoy a full day at your own pace. Explore Bali’s streets, shops, art galleries, or cafés, or relax on its beautiful beaches. Optional activities include water sports, spa treatments, or cultural performances. Capture memories of Bali’s lush landscapes, rice terraces, and vibrant culture. Return to your hotel for an overnight stay.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Departure\", \"description\": \"After breakfast, check out and transfer to Bali Airport for your departure. Take home unforgettable memories of Bali’s temples, culture, scenic beauty, and warm hospitality, concluding your luxurious island getaway.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Bali\"]','[\"City Tours\", \"Water Activities\", \"Luxury Experiences\"]',NULL,NULL,NULL,0,1,'2025-12-22 11:42:11','2025-12-22 11:44:34'),(11,323,'ghandruk-tour-4n-5d','Ghandruk Tour 4N 5D','','','This 5-day Pokhara and Ghandruk tour offers a perfect mix of scenic flights, Himalayan trekking, cultural village life, and spiritual sightseeing. Enjoy the beauty of Phewa Lake in Pokhara, trek through charming mountain villages to Ghandruk with stunning Annapurna views, and explore Nepal’s iconic heritage sites in Kathmandu, including Swayambhunath and Pashupatinath. Ideal for a short yet enriching Himalayan experience.',0.00,NULL,1,0,NULL,'5 days',NULL,'2-8','',0.00,0,'','/uploads/tours/ghandruk-tour-4n-5d/tour_1766568139456.jpg','[\"/uploads/tours/ghandruk-tour-4n-5d/tour_1766568100815.jpg\", \"/uploads/tours/ghandruk-tour-4n-5d/tour_1766568101032.jpg\", \"/uploads/tours/ghandruk-tour-4n-5d/tour_1766568101288.jpg\"]','[\"Scenic domestic flights between Kathmandu and Pokhara\", \"Peaceful boating experience on Phewa Lake\", \"Short and rewarding trek to the beautiful Gurung village of Ghandruk\", \"Panoramic views of Annapurna South and Machhapuchhre (Fishtail)\", \"Authentic village life and cultural experience in Ghandruk\", \"Sunrise views over the Himalayan range\", \"Sightseeing in Pokhara and Kathmandu UNESCO heritage sites\", \"Evening aarti at the sacred Pashupatinath Temple\"]','[\"Airport pick-up and drop-off as per itinerary\", \"Kathmandu–Pokhara–Kathmandu domestic flights\", \"All ground transportation\", \"Hotel accommodation\", \"Breakfast during the tour\", \"Experienced trekking guide\", \"Pokhara sightseeing as mentioned in the itinerary\", \"Government taxes and service charges\", \"Teahouse/lodge accommodation in Ghandruk\"]','[\"International airfare and Nepal visa fees\", \"Personal expenses (drinks, laundry, tips, phone calls, etc.)\", \"Entry fees to monuments and sightseeing sites\", \"Porter service (available on request)\", \"Any expenses not mentioned under inclusions\"]','[]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Arrival at Airport & Fly to Pokhara\", \"description\": \"Journey begins rights at Kathmandu Tribhuvan International Airport, where our representative will assist you. Take a domestic flight from Kathmandu to Pokhara (25-30 minutes). Once you arrive at Pokhara airport you will be taken to comfortable Hotel. In evening enjoy Phewa Lake views. (one hour boat ride). Return to hotel. Overnight at Pokhara Hotel.\", \"accommodation\": \"3-Star Hotel \"}, {\"day\": 2, \"meals\": \"Breakfast & Dinner\", \"title\": \"Pokhara – Drive to Nayapul – Trek to Ghandruk\", \"description\": \"In the morning, drive about 1.5 hours to Nayapul, then begin a 4-5 hours trek to Ghandruk. The routes passes through beautiful villages like Kimche and Syauli Bazaar. Once in Ghandruk, enjoy views of Annapurna South, Machhapuchhre, and visit the Gurung Museum. Stay overnight in a local teahouse or mountain lodge.\", \"accommodation\": \"Lodge\"}, {\"day\": 3, \"meals\": \"Breakfast & Dinner\", \"title\": \"Ghandruk Exploration Day\", \"description\": \"Start your morning with a stunning sunrise view over the snow-covered peaks. Today is a relaxed day in Ghandruk, allowing you to explore at your own pace. Walk through terrace fields, or simply spend time with local to understand rural mountain life. Take a short nature walk to nearby ridges or views point for photography. Return to your teahouse for a warm dinner. Overnight in Ghandruk.\", \"accommodation\": \"Lodge   \"}, {\"day\": 4, \"meals\": \"Breakfast & Dinner\", \"title\": \"Ghandruk – Trek back to Nayapul – Drive back to Pokhara\", \"description\": \"After breakfast, begin your 3-4 hours downhill trek back to Nayapul. The return is easier and offers a chance to revisit the beautiful landscapes in a more relaxed way. Once you reach Nayapul, your vehicle will drive you back to Pokhara. Check-in to your hotel spent your afternoon visiting local attractions like Devi’s Falls, Gupteshwor Mahadev Cave, or world Peace Pagoda. Return back to hotel. Overnight stay in Pokhara.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Pokhara – Fly back to Kathmandu\", \"description\": \"Early morning return back to Kathmandu by flight. Visit Swoyambhunath Stupa (Monkey Temple) and Kathmandu Durbar Square (living God Kumari). Attend Pashupatinath temple for aarti. \", \"accommodation\": \"N/A\"}]','\"\"','[\"Gandruk\"]','[\"Cultural Tours\", \"Meditation & Healing\"]',NULL,NULL,NULL,0,1,'2025-12-24 09:22:24','2025-12-24 09:23:05'),(12,306,'indo-nepal-cross-border-tour-6n-7d','Indo Nepal Cross Border Tour - 6 Nights 7 Days','Cultural','Nepal','Experience the best of Nepal with this comprehensive cross-border tour covering Pokhara\'s natural beauty, Kathmandu\'s cultural heritage, and Chitwan\'s wildlife adventure. This unique journey starts from Gorakhpur, India, and takes you through the sacred birthplace of Lord Buddha in Lumbini, the serene lakes of Pokhara, the ancient temples of Kathmandu, and the wildlife paradise of Chitwan National Park.',0.00,NULL,0,0,NULL,'7 days',NULL,'2-15 people','Easy',4.50,89,'October-April','https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Lumbini - Birthplace of Lord Buddha\", \"Pokhara valley with mountain views\", \"Kathmandu UNESCO World Heritage sites\", \"Chitwan National Park safari\", \"Manakamana Temple cable car ride\", \"Tharu cultural dance experience\"]','[\"Hotel accommodation (3-5 star options)\", \"Daily breakfast\", \"All transfers and transportation\", \"Professional guide\", \"All entrance fees\", \"Chitwan safari activities\", \"Cable car to Manakamana Temple\"]','[\"International flights\", \"Lunch and dinner (except in Chitwan)\", \"Personal expenses\", \"Travel insurance\", \"Tips for guide and staff\"]','[{\"name\": \"Cultural Tours\", \"description\": \"Visit UNESCO World Heritage sites and ancient temples\"}, {\"name\": \"Wildlife Safari\", \"description\": \"Jungle safari in Chitwan National Park\"}, {\"name\": \"Scenic Drives\", \"description\": \"Beautiful mountain and valley views\"}]','[{\"day\": 1, \"title\": \"Arrival in Gorakhpur - Lumbini - Pokhara\", \"description\": \"Arrive in Gorakhpur and meet our representative. Drive to Sunauli border crossing and complete immigration formalities. Visit Lumbini, the sacred birthplace of Lord Buddha, and explore the Maya Devi Temple and various international monasteries. Continue the scenic drive to Pokhara, Nepal\'s adventure capital. Check into hotel and enjoy the lakeside atmosphere. Evening at leisure to explore the vibrant Lakeside area.\"}, {\"day\": 2, \"title\": \"Sarangkot Excursion & Pokhara Sightseeing\", \"description\": \"Early morning drive to Sarangkot viewpoint to witness the spectacular sunrise over the Annapurna and Dhaulagiri mountain ranges. Return to hotel for breakfast. Begin full-day Pokhara city tour visiting Bindavasini Temple, the mystical David Falls (Patale Chhango), and Gupteshwor Cave with its underground waterfall. Enjoy a peaceful boat ride on Phewa Lake and visit Tal Barahi Temple situated on an island in the middle of the lake. Evening free for shopping and relaxation.\"}, {\"day\": 3, \"title\": \"Pokhara to Kathmandu via Manakamana\", \"description\": \"After breakfast, begin the scenic drive to Kathmandu. En route, stop at Kurintar and take the thrilling cable car ride to Manakamana Temple, dedicated to the Hindu goddess Bhagwati. The temple is believed to fulfill the wishes of devotees. Enjoy panoramic mountain views during the cable car journey. Continue drive to Kathmandu and check into hotel. Evening at leisure to explore Thamel, the tourist hub of Kathmandu.\"}, {\"day\": 4, \"title\": \"Kathmandu City Sightseeing\", \"description\": \"Full day exploration of Kathmandu\'s UNESCO World Heritage sites. Begin with Pashupatinath Temple, the most sacred Hindu temple dedicated to Lord Shiva, located on the banks of the holy Bagmati River. Visit Jala Narayan Temple and then proceed to Swayambhunath Stupa (Monkey Temple), offering panoramic views of Kathmandu Valley. Continue to Boudhanath Stupa, one of the largest Buddhist stupas in the world and a center of Tibetan Buddhism. End the day at Kathmandu Durbar Square, the ancient royal palace complex with intricate wood carvings and the living goddess Kumari\'s residence.\"}, {\"day\": 5, \"title\": \"Kathmandu to Chitwan\", \"description\": \"After breakfast, drive to Chitwan National Park, Nepal\'s first national park and a UNESCO World Heritage site. Upon arrival, check into jungle resort and enjoy welcome drinks. In the afternoon, visit a traditional Tharu village to learn about the indigenous culture and lifestyle of the Tharu people. Experience their unique architecture, customs, and way of life. In the evening, enjoy an authentic Tharu stick dance performance showcasing their rich cultural heritage. Dinner at the resort with traditional Tharu cuisine.\"}, {\"day\": 6, \"title\": \"Chitwan Safari Activities\", \"description\": \"Full day of exciting jungle activities in Chitwan National Park. Begin with a canoe trip along the Rapti River to spot crocodiles, various bird species, and other wildlife. Visit the Elephant Breeding Center to learn about conservation efforts. Take a guided jungle walk with experienced naturalists to discover the park\'s diverse flora and fauna. The highlight of the day is the elephant or jeep safari through the dense jungle in search of the elusive one-horned rhinoceros, Bengal tigers, leopards, and various deer species. Evening at leisure at the resort.\"}, {\"day\": 7, \"title\": \"Chitwan to Gorakhpur Departure\", \"description\": \"After breakfast and final moments in the jungle paradise, begin the drive back to Gorakhpur. En route, enjoy the changing landscapes from the Terai plains to the Indian border. Complete exit formalities at Sunauli border and continue to Gorakhpur. Transfer to railway station or airport for onward journey, carrying unforgettable memories of Nepal\'s cultural heritage, natural beauty, and wildlife encounters.\"}]','\"Basic fitness level required for walking and light activities.\"','[]','[]',NULL,NULL,NULL,0,1,'2024-12-30 10:00:00','2025-12-18 04:22:40'),(13,316,'kailash-aerial-darshan-02-nights-03-days','Kailash Aerial Darshan - 02 Nights 03 Days',NULL,NULL,'This 3-day spiritual journey offers a unique and comfortable way to seek the blessings of Mount Kailash and Lake Mansarovar via a specialized chartered flight from Nepalgunj. Designed for maximum convenience, this tour eliminates the need for high-altitude trekking, passports, or complex visa processes, making the divine \"Darshan\" accessible to everyone regardless of age. Guests will enjoy 5-star hospitality at Hotel Soaltee, dedicated ground assistance from Lucknow, and expert guided services, ensuring a seamless and soulful pilgrimage experience.',600.00,NULL,0,0,NULL,'3 days',NULL,'',NULL,0.00,0,'','/uploads/destinations/tours/tours_1766067805331.jpg','[]','[\"Chartered Flight: Scenic aerial view of Mt. Kailash and Lake Mansarovar.\", \"Effortless Darshan: No trekking or physical strain, making it ideal for senior citizens.\", \"Documentation: No passport or China visa required for Indian citizens.\", \"Premium Stay: 02 nights at the 5-Star Hotel Soaltee with full board meals.\", \"Complete Package: Includes private AC transfers, guides, and spiritual gifts.\", \"Quick Trip: A comprehensive 3-day spiritual journey starting from Lucknow.\"]','[\"Traditional welcome drinks on arrival (Non alcoholic)\", \"02 Nights accommodation at Kathmandu Hotel on AP basis(Breakfast, Lunch & Dinner)\", \"01 litter mineral water per day\", \"Hindi/English speaking tour guide for entire trip\", \"Gift from the company Kailash Tirtham(jal),Rudraksha Mala\", \"All sightseeing and excursions as mentioned in the itinerary.\", \"All transfers & sightseeing by private air condition vehicle.\", \"Round trip Transportation for Lucknow - Nepalgunj - Lucknow  by Private vehicle\", \"Vehicles are not to be at disposal and are available as per itinerary only (point to point basis).\", \"All current Nepal Government taxes \"]','[\"Domestic/International Airfare \", \"Insurance Fee\", \"Personal expenses, tipping and any other services which are not mentioned in the above inclusion\"]','[]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Arrive in Lucknow - Drive to Nepalgunj(190 km, 04/05 Hrs) \", \"description\": \"Upon arrival in Lucknow Airport, you will be greeted and assisted by our representative after completing your airport process, drive to Nepalgunj,arrival at Nepalgunj, transfer to Hotel for check-in. Overnight at Nepalgunj Hotel.\", \"accommodation\": \"Hotel Soaltee - 4 Star\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kailash MansarovarDarshan Chartered Flight(Aerial view - 1.5 Hrs)\", \"description\": \"After breakfast in the morning our guide will organise group transfer from hotel to Nepalgunj airport where the chartered flight for Kailash Darshan,You will get mesmerizing darshan of holy Mount Kailash and Lake Mansarovar from the window of your flight while flying over the mountains near nepal-Tibet border. The view of mountain and lake from the flight is completely subject to clear weather,back to Nepalgunj transfer to hotel.Overnight at Nepalgunj.\", \"accommodation\": \"Hotel Soaltee - 4 Star\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch\", \"title\": \"Nepalgunj - Drive to Lucknow departure transfer(190 km,04/05 Hrs)\", \"description\": \"After breakfast, the morning will be comparatively free and closer to the time of your flight,drive to Lucknow airport on time to board your flight for onward journey. \", \"accommodation\": \"Hotel Soaltee - 4 Star\"}]','\"\"','[\"Tibet\"]','[\"Pilgrimage\", \"Cultural Tours\"]',NULL,NULL,NULL,0,1,'2025-12-18 14:19:26','2025-12-18 19:51:36'),(14,13,'kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route','Kailash Mansarovar Yatra 08 Nights 09 Days ex Lucknow - Helicopter Route','Spiritual','Tibet, China','Experience the sacred Kailash Mansarovar Yatra via helicopter route from Lucknow. This premium 9-day journey combines helicopter flights with the spiritual pilgrimage, offering comfort and convenience while maintaining the sacred essence of the yatra. The helicopter route significantly reduces travel time while providing breathtaking aerial views of the Himalayas.',3021.00,NULL,1,1,6.00,'9 days',NULL,'25+ People','Moderate',4.70,89,'May to September','/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766141287544.jpg','[\"/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766923144411.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766923144769.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766923145114.JPG\", \"/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766923151553.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-08-nights-09-days-ex-lucknow-helicopter-route/tour_1766923151895.JPEG\"]','[\"Helicopter flights from Simikot to Hilsa for comfort and time-saving\", \"Sacred Mount Kailash Parikrama (circumambulation)\", \"Holy bath and prayers at Lake Mansarovar\", \"Reduced travel time with premium helicopter transfers\", \"Professional spiritual guide with deep knowledge\", \"Comfortable accommodation throughout the journey\", \"Medical support and Gamow bag for altitude safety\", \"Small group experience for personalized attention\", \"Aerial views of the majestic Himalayas\", \"Visit to ancient Tibetan monasteries and temples\"]','[\".Traditional welcome on arrival \", \"01 Night accommodation at Nepalgunj on Double/Twin sharing basis(3 Star Premium)\", \"01 Night accommodation iat Simikot on sharing basis(Hotels and Guest house) \", \"01 Night accommodation at Hilsa on sharing basis(Guest house) \", \"05 Night accommodation in Tibet on sharing basis(Hotels and Guest houses) \", \"Nepalgunj - Simikot - Nepalgunj flight cost(17 Pax)\", \"Simikot - Hilsa - Simikot helicopter cost\", \"Tibet travel Permit & Visa fees\", \"Humla trekking Permit and fees\", \"English speaking Tibetan guide for customers formalities\", \"Nepali Supporting Staff(cook, Sherpa & helper) 5:1 basis \", \"Buffet vegetarian meals during Yatra on AP basis(Breakfast,Lunch & Dinner)\", \"Nepali experienced Team Leader/Guide during Yatra\", \"Border crossing assistance and formalities\", \"Supporting truck to carry equipment \", \"Mansarovar and Kailash Yatra Permit fees\", \"Duffel bag for carrying goods during Yatra\", \"Back pack bag for personal items to carry and Cap\", \"Warm down Jacket refundable \", \"First aid medical kit bag & Oxygen cylinder \", \"Emergency evacuation management during Yatra\", \"Round trip transportation in Tibet AC Luxury coach\", \"Arrival and departure transfer with assistance by A/C Vehicle  \", \"All sightseeing and excursions as mentioned in the itinerary.\", \"Vehicles are not to be at disposal and are available as per itinerary only (point to point basis).\", \"Kailash Yatra appreciation certificate  \"]','[\"Personal expenses and travel Insurance\", \"Medical expenses and Emergency rescue evacuation expenses\", \"Horses,Pony and porter during Kailash Parikrama \", \"Tips for Guide, Porter, driver and personal expenses\", \"Extra Hotel charges in Nepal side if early return from Tibet\", \"Any additional cost due to natural calamities and unforeseen circumstances\", \"Visa splitting charge and extra transportation cost, if returning early from Yatra\"]','[\"Helicopter sightseeing flights\", \"Sacred Mount Kailash Parikrama\", \"Holy bath at Lake Mansarovar\", \"Prayer and meditation sessions\", \"Homa ceremony at Mansarovar\", \"Visit to Tibetan monasteries\", \"High altitude trekking\", \"Cultural interaction with locals\", \"Photography of sacred sites\", \"Spiritual discourse sessions\"]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Arrival in Lucknow - Drive to Nepalgunj (200 km ,5/6 Hrs 150 M)\", \"altitude\": \"150m\", \"description\": \"Upon arrival in Lucknow Airport, you will be greeted and assisted by our representative after completing your custom formalities, drive to Nepalgunj(190 Km,6 Hrs)Arrive at Nepalgunj transfer to the Hotel for check-in.overnight at Nepalgunj Hotel.\", \"accommodation\": \"4 Start Hotel Soaltee\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Nepalgunj - Fly to Simikot (2800M,45 Minutes)\", \"altitude\": \"2800m\", \"description\": \"After breakfast transfer to domestic airport ,fly to Simikot by arrive at Simikot airport, transfer to hotel for check in. Evening short walk to lord Shiva Temple back to hotel .Overnight at Simikot. \", \"accommodation\": \"Standard Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Simikot - Fly to Hilsa by Helicopter - Drive to Purang (3700M ,35 Km ,1.5 Hrs)\", \"altitude\": \"3700m\", \"description\": \"After breakfast fly to Hilsa by Helicopter (20 Min, 15 Kg weight limit for baggage) wait for the others member to arrive at Hilsa (since it is a group visa and everyone have to enter Tibet side in one group) complete immigration & custom formalities in Nepal and China side then continue drive to Purang (30 Km ,1 Hrs ,on the way we have to pass up to 2 Checkpoints where checking might take up to 1 hour each check post) transfer to the Hotel for check-in.overnight at Purang hotel.\", \"accommodation\": \"Deluxe Hotel (Shared , Attached bathroom)\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Acclimatization Day at Purang(3900M)\", \"altitude\": \"3900m\", \"description\": \"Important acclimatization day to adjust to high altitude. Light activities around Purang town. Medical check-up and preparation for higher altitudes. Visit local market and interact with Tibetan culture. Rest and hydration are essential.\", \"accommodation\": \"Deluxe Hotel (Shared , Attached bathroom)\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Purang - Drive to Mansarovar Parikrama (4550M,102 Km 4 Hrs ,Holy bath,Pooja,Homa)\", \"altitude\": \"4550m\", \"description\": \"After breakfast drive to Rakshas Tal (40 km, 1.5 hrs) on the way you will have to pass a check point.After reaching Rakshas Tal you will see Gurla Mandhata Parvat & first view of Mt.Kailash south face and Manasarovar Lake, 40 Km drive we reach Manasarovar then start Parikrma of Mansarovar Lake by Vehicle and Overnight at the Shore of the Lake.\", \"accommodation\": \"Pramath Asram (Dormitory room, Common Bathroom)\"}, {\"day\": 6, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Mansarovar - Drive to Yamdwar(58 km,2 Hrs) - Trek to Diraphuk (4860M,12 Km, First Day of Kora)\", \"altitude\": \"4860m\", \"description\": \"After breakfast short drive to Darchen, visit Yamdwar.This is starting point of Kora.We will trek to Diraphuk which is 12 km trek (7/8 Hrs) crossing west face of Mt.Kailash,You will visit North face of Mt.Kailash. Arrive at Diraphuk ,transfer to the Guest house for check-in.overnight at Diraphuk.\", \"accommodation\": \"Guest House (Dormitory, Common Bathroom)\"}, {\"day\": 7, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Dirapuk - Trek to Zutalphuk (4600M,22 Km, 2nd Day of kora-Cross Dolmala Pass)\", \"altitude\": \"4600m\", \"description\": \"After breakfast trek to Dolma -La Pass and trek to Zutalphuk(22 Km,9/10 hrs Trek).This is the most difficult journey throughout  the the yatra since you have to trek up to (5630m) height. From decent to Gaurikund and trek to Zutulphuk following river. Arrive at Zutalphuk transfer to the Guest house for check-in.overnight at Zutalphuk.\", \"accommodation\": \"Guest House (Dormitory, Common Bathroom)\"}, {\"day\": 8, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Zutalphuk -Trek to Darchen(08 Km ,3 Hrs)-Drive to Hilsa  (3700m)\", \"altitude\": \"3700m\", \"description\": \"After breakfast short trek ( 8 Km ,2 Hrs) and reach to the point where our coach will be waiting and we will drive to Darchen and merge with other member  who were waiting and drive to Hilsa.China-Nepal both side border formalities transfer to hotel for check in.Overnight at Hilsa. \", \"accommodation\": \"Hotel Snowland (Dormitory, Common Bathroom)\"}, {\"day\": 9, \"meals\": \"Breakfast. Lunch\", \"title\": \"Hilsa - Fly to Simikot by Heli - Fly to Nepalgunj by Flight - Drive to Lucknow\", \"altitude\": \"150m\", \"description\": \"After breakfast fly to Simikot (20 Mins) by Helicopter, catch a flight from Simikot to Nepalgunj (50 mins) arrive at Nepalgunj transfer to hotel for fresh up later drive to Lucknow for final departure.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Tibet\"]','[\"Cultural Tours\", \"Pilgrimage\"]',NULL,NULL,NULL,1,1,'2026-07-05 20:11:55','2025-12-28 11:59:15'),(15,314,'kailash-mansarovar-yatra-11-nights-12-days-ex-kathmandu-helicopter-route','Kailash Mansarovar Yatra 11 Nights 12 Days ex Kathmandu - Helicopter Route',NULL,NULL,'Experience the sacred Kailash Mansarovar Yatra via helicopter route from Kathmandu. This premium 12-day journey combines helicopter flights with the spiritual pilgrimage, offering comfort and convenience while maintaining the sacred essence of the yatra. The helicopter route significantly reduces travel time while providing breathtaking aerial views of the Himalayas.',3250.00,NULL,1,1,6.00,'12 days',NULL,'25+ People',NULL,0.00,0,'','/uploads/destinations/tours/tours_1766064650576.webp','[]','[]','[\"Traditional welcome on arrival \", \"03 Night accommodation at Kathmandu on sharing Twin/Double basis(Premium\", \"01 Night accommodation at Nepalgunj on Double/Twin sharing basis(Premium)\", \"01 Night accommodation at Simikot on sharing basis(Guest house) \", \"01 Night accommodation at Hilsa on sharing basis(Guest house) \", \"05 Night accommodation in Tibet on sharing basis(Hotel Basis) \", \"Kathmandu - Nepalgunj – Kathmandu flight cost \", \"Nepalgunj - Simikot - Nepalgunj flight cost(17 Pax at a time)\", \"Simikot - Hilsa - Simikot helicopter cost(04 Pax carry at a time)\", \"Tibet travel Permit & Visa fees\", \"Humla Trekking Permit and fees\", \"English speaking Tibetan guide for customers formalities\", \"Nepali Supporting Staff(cook,Sherpa & helper) 5:1 basis \", \"Buffet vegetarian meals during Yatra on AP basis(Breakfast, Lunch & Dinner)\", \"Nepali experienced Team Leader/Guide during Yatra\", \"Supporting truck to carry equipment \", \"Mansarovar and Kailash Yatra Permit fees\", \"Duffel bag for carrying goods during Yatra\", \"Back pack bag for personal items to carry and Cap\", \"Warm down Jacket refundable \", \"First aid medical kit bag & Oxygen cylinder \", \"Emergency evacuation management during Yatra\", \"Round trip transportation in Tibet AC Luxury coach\", \"Arrival and departure transfer with assistance by A/C Vehicle  \", \"All sightseeing and excursions as mentioned in the itinerary.\", \"Vehicles are not to be at disposal and are available as per itinerary only (point to point basis).\", \"Kailash Mansarovar Yatra appreciation certificate  \"]','[\"Personal expenses and travel Insurance\", \"Medical expenses and Emergency rescue evacuation expenses\", \"Horses,Pony and porter during Kailash Parikrama \", \"Tips for Guide, Porter, driver and personal expenses\", \"Extra Hotel charges in Kathmandu if early return from Tibet\", \"Any additional cost due to natural calamities and unforeseen circumstances\", \"Visa splitting charge and extra transportation cost, if returning early from Yatra\", \"5 % GST If you pay India account\"]','[]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Arrival Kathmandu (1300m\", \"description\": \"Upon arrival in Kathmandu Airport, you will be greeted and assisted by our representative after completing your custom formalities,transfer to the hotel for check-in. Overnight at Kathmandu Hotel.\", \"accommodation\": \"Best Western Plus - 4 Start Hotel \"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu Sightseeing - Fly to Nepalgunj (150M ,1 Hrs)\", \"description\": \"After breakfast Kathmandu city sightseeing tour, visit  Pasupatinath Temple,Bouddhanath Stupa(World heritage site),Jala Narayan Temple(sleeping Vishnu) back to hotel take lunch evening fly to Nepalgunj,arrive at Nepalgunj transfer to hotel for check in.Overnight at Nepalhunj.\", \"accommodation\": \"Hotel Soaltee - 4 Star\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Nepalgunj - Fly to Simikot (2800M ,50 Min)\", \"description\": \"After breakfast transfer to domestic airport ,fly to Simikot, arrive at Simikot airport, transfer to hotel for check in. Evening short walk to lord Shiva Temple back to hotel. Overnight at Simikot. \", \"accommodation\": \"Standard Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Simikot - Fly to Hilsa by Helicopter - Drive to Purang (3700M,35 km,2 Hrs)\", \"description\": \"After breakfast fly to Hilsa by Helicopter (20 Min, 15 Kg weight limit for baggage) wait for the others member to arrive at Hilsa (since it is a group visa and everyone have to enter Tibet side in one group) complete immigration and custom formalities in Nepal - China both side continue drive to Purang ,on the way we have to pass up to 2 Checkpoints where checking might take upto 1 hour each check post) transfer to the Hotel for check-in.overnight at Purang hotel.\\n\\n\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Purang Acclimatization Day (3900M)\", \"description\": \"After breakfast all day is free for acclimatization today you can buy Kailash kora clothes,bottle,sticks and others trekking gears for parikrama.Overnight at Purang hotel.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 6, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Purang - Drive to Mansarovar Parikrama (4550M,102 km,4 Hrs - Holy bath,Pooja,Homa)\", \"description\": \"After breakfast drive to Rakshas Tal (40 km, 1.5 hrs) on the way you will have to pass 1 check point. After reaching Rakshas Tal you will see Gurla Mandhata Parvat and first view of Mt.Kailash south face and Manasarovar Lake, 40 Km drive we reach Mansarovar continue Parikrma of Mansarovar lake by Vehicle (102 Km,4 Hrs) and Overnight at the Shore of the Lake.\\n\\n\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 7, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Mansarovar - Drive to Yamdwar (60 Km,2 Hrs)- Trek to Diraphuk (4860M, 12 Km - First Day of Kora)\", \"description\": \"After breakfast short drive to Darchen, visit Yamdwar.This is starting point of Kora.We will trek to Diraphuk which is 12 km trek (7/8 Hrs) crossing west face of Mt.Kailash,You will visit North face of Mt.Kailash. Arrive at Diraphuk ,transfer to the Guest house for check-in.overnight at Diraphuk.\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 8, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Diraphuk - Trek to Zutalphuk (4600M,22 Km - 2nd Day of kora Cross Dolmala Pass)\", \"description\": \"After breakfast trek to Dolma -La Pass and trek to Zutalphuk(22 Km,9/10 hrs Trek).This is the most difficult journey throughout  the the yatra since you have to trek up to (5630m) height. From decent to Gaurikund & trek to Zutulphuk following river. Arrive at Zutalphuk transfer to the Guest house for check-in.overnight at Zutalphuk.\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 9, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Zutalphuk - Trek to Darchen(08 Km/3 Hrs - Drive to Hilsa  (3700M,100 km 03 Hrs)\", \"description\": \"After breakfast short trek ( 8 Km ,2 Hrs) and reach to the point where our coach will be waiting and we will drive to Darchen and merge with other member  who were waiting and drive to Hilsa border formalities both side China - Nepal, transfer to hotel for check in.Overnight at Hilsa.\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 10, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Hilsa -Fly to  Simikot by Heli -Fly to Nepalgunj – Fly to Kathmandu\", \"description\": \"After breakfast fly to Simikot by Helicopter (20 Mins), Take connecting flight to  Nepalgunj again fly back to Kathmandu.arrival at Kathmandu transfer to hotel for check in. Overnight at Kathmandu.\\n\\n\", \"accommodation\": \"Best Western Plus - 4 Star\"}, {\"day\": 11, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Bhaktapur Durbar Squire and Doleshwar Mahadev Temple\", \"description\": \"After breakfast fly to Simikot by Helicopter (20 Mins), Take connecting flight to  Nepalgunj again fly back to Kathmandu.arrival at Kathmandu transfer to hotel for check in. Overnight at Kathmandu.\", \"accommodation\": \"Best Western Plus - 4 Star\"}, {\"day\": 12, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu departure transfer \", \"description\": \"After breakfast we will be provide appreciation certificate of Kailash Mansarovar Yatra later drop to airport for final departure.\\n\\n\", \"accommodation\": \"N/A\"}]','\"\"','[\"Tibet\"]','[\"Pilgrimage\", \"Cultural Tours\"]',NULL,NULL,NULL,1,1,'2025-12-18 13:01:50','2025-12-18 21:07:57'),(16,11,'kailash-mansarovar-yatra-13-nights-14-days-overland','Kailash Mansarovar Yatra 13 Nights 14 Days Overland','Spiritual','Tibet, China','Embark on the sacred journey to Mount Kailash and Lake Mansarovar, one of the most revered pilgrimage sites in Hinduism, Buddhism, Jainism, and Bon religion. This 13-day overland journey from Kathmandu offers a transformative spiritual experience through the mystical landscapes of Tibet.',2650.00,NULL,1,1,6.00,'14 days',NULL,'25+ People','Challenging',4.80,156,'May, June, July, August, September, October','/uploads/destinations/tours/tours_1762066264929.webp','[\"/uploads/destinations/tours/tours_1766060386383.jpg\", \"/uploads/destinations/tours/tours_1766060397550.jpg\", \"/uploads/destinations/tours/tours_1766060402623.jpg\", \"/uploads/destinations/tours/tours_1766060407885.jpg\", \"/uploads/destinations/tours/tours_1766060421857.jpg\"]','[\"Sacred Mount Kailash Parikrama (circumambulation)\", \"Holy bath and prayers at Lake Mansarovar\", \"Visit to ancient Tibetan monasteries\", \"Crossing Dolma La Pass at 5,630m\", \"Spiritual journey through pristine Tibetan landscapes\", \"Cultural immersion in Tibetan Buddhist traditions\", \"Professional guide with spiritual knowledge\", \"Gamow bag for altitude sickness prevention\"]','[\"Traditional welcome on arrival \", \"03 Night accommodation at Kathmandu on sharing Twin/Double basis(03 Star Premium)\", \"01 Night accommodation at Kyirung on sharing basis(Basic Hotel)\", \"09 Night accommodation in Tibet on sharing basis(Hotels  and Guest houses) \", \"Professional guide throughout the journey\", \"Tibet travel Permit & Visa fees\", \"English speaking Tibetan guide for customers formalities\", \"Nepali Supporting Staff(cook,Sherpa & helper) 5:1 basis \", \"Buffet vegetarian meals during Yatra on AP basis(Breakfast,Lunch & Dinner)\", \"Nepali experienced Team Leader/Guide during Yatra\", \"Supporting truck to carry equipment \", \"Mansarovar and Kailash Yatra Permit fees\", \"Duffel bag for carrying goods during Yatra\", \"Duffel bag for carrying goods during Yatra\", \"Back pack bag for personal items to carry and Cap\", \"Warm down Jacket refundable \", \"First aid medical kit bag & Oxygen cylinder \", \"Emergency evacuation management during Yatra\", \"Round trip transportation in Tibet AC Luxury coach\", \"Kathmandu - Rasuwagadi - Kathmandu A/C Vehicle\", \"Arrival and departure transfer with assistance by A/C Vehicle  \"]','[\"Personal expenses and travel Insurance\", \"Medical expenses and Emergency rescue evacuation expenses\", \"Tips for Guide, Porter, driver and personal expenses\", \"Extra Hotel charges in Kathmandu if early return from Tibet\", \"Any additional cost due to natural calamities and unforeseen circumstances\", \"Visa splitting charge and extra transportation cost, if returning early from Yatra\", \"5 % Vat GST India Government\", \"Emergency evacuation costs\"]','[\"Sacred pilgrimage\", \"High altitude trekking\", \"Cultural exploration\", \"Spiritual ceremonies\", \"Photography\", \"Meditation\"]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Arrival in Kathmandu (1300m)\", \"activities\": [\"Airport transfer\", \"Hotel check-in\", \"Yatra briefing\"], \"description\": \"Upon arrival at Kathmandu International Airport, you will be greeted and assisted by our representative after completing custom formalities. Transfer to hotel for check-in. Evening yatra briefing session before dinner covering important aspects of the Kailash Mansarovar Yatra.\", \"accommodation\": \"Best Western Plus - 4 Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu Temple Visit\", \"activities\": [\"Temple visits\", \"Cultural sightseeing\", \"Yatra preparation\"], \"description\": \"After breakfast, embark on Kathmandu city sightseeing tour. Visit Pashupatinath Temple, Boudhanath Stupa (World Heritage Site), Jal Narayan Temple (Sleeping Vishnu), and Kathmandu Durbar Square (Living God Kumari). Return to hotel for packing and preparation for the yatra.\", \"accommodation\": \"Best Western Plus - 4 Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \": Kathmandu - Drive to Kyirung(1600 m)\", \"activities\": [\"Border crossing\", \"Immigration formalities\"], \"description\": \"Our representative will pick up you, drive to Kyirung(145 Km ,05/06 Hrs),arrive at Kyirung transfer to hotel for check in. Overnight at  Kyirung Guest house.\", \"accommodation\": \"Standard Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kyirung- Drive to  Gyirung County(2800m)\", \"activities\": [\"Tibet entry\", \"Altitude acclimatization\", \"Rest\"], \"description\": \"After breakfast complete immigration and custom formalities in Nepal and China both side continue drive to Gyirung(35 Km ,1 Hrs 2800m). Arrive at Gyirung transfer to hotel for check in. overnight at Gyirung.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Gyirung County Acclimatation(2800m)\", \"activities\": [\"High altitude driving\", \"Brahmaputra River crossing\", \"Landscape viewing\"], \"description\": \"After breakfast you are free for visit around Gyirung county or shopping . Overnight at Gyirung County.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 6, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Gyirung - Drive to Saga (4500M ,270 km 06/07 Hrs)\", \"activities\": [\"Sacred lake arrival\", \"Spiritual preparation\"], \"description\": \"After breakfast drive to Saga crossing Bramhaputra river(270 km, 6/7 Hrs),Arrive at Sanga transfer to hotel for check in. Overnight at Saga hotel.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 7, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Saga - Drive to  Mansarovar (4550M ,470 km 08/09 Hrs)\", \"activities\": [\"Lake parikrama\", \"Holy bath\", \"Puja ceremonies\", \"Kailash base camp arrival\"], \"description\": \"After breakfast drive towards Mansarovar lake (470 Km, 08/09 Hrs),Arrive at Mansarovar lake transfer to guest house for check in .Overnight at Mansarovar lake.\", \"accommodation\": \"Pramath Asram (Dormitory room, Common Bathroom)\"}, {\"day\": 8, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Mansarovar Parikrama - Drive to Darchen (4600 m)\", \"activities\": [\"Kailash parikrama start\", \"Yamdwar darshan\", \"High altitude trekking\"], \"description\": \"After breakfast Parikrma of Mansarovar lake by vehicle (102 Km,3 Hrs) take Holy bath, Perform Puja(prayer ritual, Homa at Mansarovar lake, continue drive to Darchen (58 Km ,1.5 Hrs).Arrive at Darchen transfer to hotel for check in. overnight at Darchen.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 9, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Darchen Darshan Yamdwar - Trek to Diraphuk (4860m, 12 Km - First Day of Kora )\", \"activities\": [\"Dolma La Pass crossing\", \"High altitude trekking\", \"Spiritual significance\"], \"description\": \"After breakfast short drive to Yamddwar, visit Yama Dwar.This is starting point of Kora.We will trek to Diraphuk which is 12 km trek (7/8 Hrs) crossing west face of Mt.Kailash,You will visit North face of Mt.Kailash. Arrive at Diraphuk transfer to hotel for check in. Overnight at Diraphuk. Overnight at a Hotel in Diraphuk.\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 10, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Diraphuk - Trek to Zutalphuk (4600M,22 Km - 2nd day of Kora)\", \"activities\": [\"Parikrama completion\", \"Return journey\", \"Celebration\"], \"description\": \"After breakfast trek to Dolma - La Pass and proceed to Zutalphuk(22 Km,12 hrs Trek). This is the most difficult journey throughout the the Yatra since you have to trek up to (5630m) height. From decent to Gaurikund and trek to Zutulphuk following river. Arrive at Zutalphuk transfer, check in to hotel. overnight at Zutalphuk at Huest house.\", \"accommodation\": \"Basic Hotel(Dormitory room, Common Bathroom)\"}, {\"day\": 11, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Zutalphuk - Trek to Darchen(08 Km, 03 Hrs) - Drive to Saga (4500M - 3rd day of Kora)\", \"activities\": [\"Return journey\", \"Altitude descent\", \"Rest and recovery\"], \"description\": \"After breakfast short trek( 8 Km,2 Hrs) and reach to the point where our coach will be waiting and we will drive to Darchen and merge with other member who were waiting and drive to Saga. Arrive at saga transfer to hotel for check in.overnight at saga.\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 12, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Saga - Drive to Gyirung County(2800M ,270 Km,07 Hrs)\", \"activities\": [\"Border crossing\", \"Return to Kathmandu\", \"Rest and recovery\"], \"description\": \"After breakfast drive to Gyirung(270 km, 7 hrs). Arrive at Gyirung transfer to hotel for check in. Overnight at Gyirung\", \"accommodation\": \"Deluxe Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 13, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Gyirung County  - Drive to Kathmandu  (1300 M, 200 Km 08 Hrs))\", \"activities\": [\"Airport transfer\", \"Departure\"], \"description\": \"After breakfast drive to Kathmandu crossing Nepal - China both side Border formalities continue drive to Kathmandu arrive at Kathmandu  transfer to hotel for check in.Overnight at Kathmandu.\", \"accommodation\": \"Best Western Plus - 4 Star Hotel\"}, {\"day\": 14, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu departure transfer \", \"description\": \"After breakfast we will be provide appreciation certificate of Kailash Mansarovar Yatra later drop to airport for final departure\", \"accommodation\": \"N/A\"}]','\"Basic fitness level sufficient.\"','[\"Tibet\"]','[\"Cultural Tours\", \"Pilgrimage\"]',NULL,NULL,NULL,1,1,'2025-09-19 04:13:16','2025-12-18 12:45:27'),(17,315,'kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-','Kailash Mansarovar Yatra Ex Lhasa - 10 Nights 11 Days ','','','Experience a sacred and life-changing pilgrimage to Mount Kailash and Lake Mansarovar starting from Lhasa. This spiritual journey includes acclimatization and sightseeing in Lhasa, a scenic drive across the Tibetan Plateau, a holy dip at Lake Mansarovar, and the divine Parikrama of Mount Kailash. Carefully organized with experienced guides, permits, and best available accommodations, this yatra offers a safe, meaningful, and unforgettable spiritual experience.',0.00,NULL,1,0,NULL,'11 days',NULL,'','',0.00,0,'','/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766141032912.webp','[\"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922966749.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922967093.JPG\", \"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922969418.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922970192.jpg\", \"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922970325.JPEG\", \"/uploads/tours/kailash-mansarovar-yatra-ex-lhasa-10-nights-11-days-/tour_1766922970450.JPEG\"]','[]','[\"03 Night accommodation at Kathmandu on 5 Star Hotel – Hotel Aloft / Hotel Dusit \", \"03 nights accommodation at 05 Star Hotel in Lhasa\", \"01 nights accommodation at Ali or Purang on 4-star Hotel\", \"Accommodation at guesthouse at Mansarovar, Dirapuk & Zuthulphuk on a sharing basis – 1 night at each place (Common sharing Tibetan style toilet)\", \"Sightseeing during Kathmandu Stay (As per the itinerary)\", \"Tibet group paper Visa Fee\", \"All vegetarian meals (breakfast, lunch & dinner)\", \"Transportation in Tibet by luxury A/C coach\", \"Supporting truck to carry equipment\", \"English speaking Tibetan guide\", \"All necessary travel & trekking permit as per our itinerary\", \"Supporting crew members (Cooks, Helpers & Sherpas)\", \"Oxygen cylinders for emergency use & medical kit bag\", \"1 x duffle bag, 1 x backpack, 1 x cap, 1 x passport holders, 1 x waterproof windcheater jacket as a souvenir gift from our company\", \"Kailash Yatra completion certificate\", \"Escort for airport pick up & drop off\", \"All applicable taxes & service charges\"]','[\"Entrance fee during Sightseeing in Nepal\", \"Chandragiri Cable Car fare\", \"Air ticket to Kathmandu & return back to home.\", \"Air ticket from Kathmandu – Lhasa – Kathmandu\", \"Travel insurance / Rescue and evacuation service\", \"Multiple entry Nepal Visa fee for foreigners\", \"Horse and Potter hiring during the Parikrama ( Approx 4000 Chinese  Yuan for both or 1200 for Porter only)\"]','[]','[{\"day\": 1, \"meals\": \"Dinner\", \"title\": \"Kathmandu Arrival (1400m) - Overnight in Kathmandu\", \"description\": \"Your Arrival Time – Airport pickup and transfer to your Hotel. Original passport and photograph collection for Chinese visa processing.\", \"accommodation\": \"The Soaltee - 5 Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Kathmandu City Sightseeing\", \"description\": \"08:00 AM – After Breakfast – Full day sightseeing of Pashupatinath Temple, ShaktiPeeth and Budhanilkantha.\", \"accommodation\": \"The Soaltee - 5 Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Kathmandu- Lhasa Flight\", \"description\": \"After Breakfast: Drive to Kathmandu airport. Take a Morning flight to Lhasa. (1 hrs 15 m). Arrive at Lhasa Gonggar Airport. Upon arrival you will be welcomed with White Khada and transfer to the Hotel. Along the way, you can enjoy the spectacular scenery of Yarlung Tsangpo River, Lhasa River, and the typical Tibetan villages.\", \"accommodation\": \"5 star Hotel - Intercontinental Lhasa\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Lhasa Sightseeing: Visit Potala Palace, Jokhang Temple and Barkhor Street\", \"description\": \"Guide will take you to the stunning Potala Palace, from top you can gaze down upon views of Lhasa. The enormous building contains a tiny world inside. Nestled at the base of the Potala Palace, Longwangtan Park awaits you. Enjoy traditional Tibetan cultural experiences and a unique viewpoint of the magnificent Potala Palace from this serene location.\\nYou will travel to the revered Jokhang Temple in the afternoon. Located in the heart of Lhasa’s old town, the Jokhang Temple was built in the seventh century. The temple’s circumference, Barkhor Street, is a fantastic location for souvenir shopping.\\n\", \"accommodation\": \"5 star Hotel - Intercontinental Lhasa\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Lhasa – Ali or Purang Flight. And Drive to Mansarovar (4550m)\", \"description\": \"Transfer to Airport to fly out to Ali Gunsa Airport or Purang Airport (4,500 m) (2 hrs flight). Pick up from the airport, drive to Mansarovar lake crossing beautiful places and stay at the shore of the Lake. Fill spiritual water. Parikrama of Mansarovar Lake by vehicle (3 hrs – 90 km). Perform Puja (prayer ritual) at Mansarovar Lake.\", \"accommodation\": \"Basic Hotel with Attached Bathroom\"}, {\"day\": 6, \"meals\": \"Breakfast at Darchen, Packed Lunch, Dinner\", \"title\": \"First Day of Outer Kora - Trek to Dirapuk (4860m)\", \"description\": \"10:00 AM – After a short drive, we will reach Tarboche and visit Yama Dwar. This is the starting point for Kora. We will trek to Dirapuk (4860 m) which is a 12 km trek (5-6 hrs). You will visit the North face of Mt. Kailash. Travelers who do not want to trek around (Parikrama) Kailash can go back to Darchen and wait for the rest of the group to arrive from Parikrama.\", \"accommodation\": \"Basic Hotel with common Bathroom\"}, {\"day\": 7, \"meals\": \"Breakfast, Packed Lunch, Dinner\", \"title\": \"Second Day of Outer Kora - On to Zuthulphuk (4670m) with Trek via Dolma La Pass\", \"description\": \"07:00AM – Trek from Dirapuk to Dolma La Pass and proceed to Zuthulphuk (22 km trek for 8-9 hours trek). The first stage of the trip is a two-hour ascent to Dolma La Pass (5700 m | 18700 ft). The trail brings us past Yamasthal on our way to Shiva-sthal, with each step bringing us closer to the Dolma-La Pass. There are some tea shops before you reach Dolma La Pass where you can have tea and hot refreshments. After Dolma La Pass, the route descends for an hour before straightening out for 2-3 hours till we reach Zuthulphuk. You’ll be able to see Gauri Kunda (The Pond of Goddess Parvati) as well while descending from Dolma la pass.\", \"accommodation\": \"Basic Hotel with common Bathroom\"}, {\"day\": 8, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Third day of Outer Kora. Kora ends. Drive to Purang or Ali\", \"description\": \"08:00AM – After a short Trek (8kms – 2 – 3hrs) and reach the point where the coach will be waiting, we will drive to Darchen and merge with other members who were waiting and drive to Ali or Purang.\", \"accommodation\": \"4 star Hotel\"}, {\"day\": 9, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Flight to Lhasa\", \"description\": \"Transfer to Airport and fly to Lhasa. Rest at Lhasa & free day for Shopping.\", \"accommodation\": \"5 star Hotel - Intercontinental Lhasa\"}, {\"day\": 10, \"meals\": \"Breakfast, Lunch and Dinner\", \"title\": \"Fly from Lhasa to Kathmandu\", \"description\": \"Fly to Kathmandu airport from Lhasa and transfer to a hotel.\", \"accommodation\": \"5 Star Hotel – Hotel Aloft / Hotel Dusit Princess or similar\"}, {\"day\": 11, \"meals\": \"Breakfast \", \"title\": \"Transfer to Kathmandu Airport\", \"description\": \"You will be free till your flight time. We will drop you at the Airport 2 hours before flight time (30 mins drive).\", \"accommodation\": \"N/A\"}]','\"\"','[\"Tibet\"]','[\"Cultural Tours\", \"Pilgrimage\"]',NULL,NULL,NULL,0,1,'2025-12-18 13:55:08','2025-12-28 12:02:33'),(18,317,'kailash-yatra-inner-kora-detailed','Kailash Yatra with Inner Kora 17 Nights 18 Days',NULL,NULL,'A high-intensity spiritual pilgrimage focusing on the \'City of the Gods.\' Beyond the standard outer circuit, this yatra leads devotees closer to the south face of Mt. Kailash to perform the Inner Kora. The journey traverses high-altitude terrain (up to 5,860m) to reach ancient meditation caves and sacred rock formations believed to be the home of Lord Shiva. This exclusive experience is designed for seasoned pilgrims seeking profound spiritual immersion through demanding high-altitude trekking and proximity to the divine summit.',0.00,NULL,0,0,NULL,'18 days',NULL,'25+ People',NULL,0.00,0,'May to mid-October','','[]','[\"Charan Sparsh: Trekking to the very base of the North Face to physically touch the mountain.\", \"Nandi Kora: A strenuous 34km circuit around Nandi Parvat, including the high Nandi Pass (5,805m).\", \"Saptarishi Caves: Visiting the cliffside caves where the seven legendary sages meditated.\", \"13 Golden Chortens: Reaching the spiritual high point at 5,860m to witness the stupas of eminent monks.\", \"Atmalingam: Darshan of the sacred natural rock formation representing the \'soul lingam\'.\", \"Gauri Kund: Rituals at the \'Lake of Compassion\' associated with Goddess Parvati.\"]','[\"Traditional welcome on arrival\", \"03 Night accommodation at Kathmandu on sharing Twin/Double basis (03 Star Premium)\", \"01 Night accommodation at Kyirung on sharing basis (Guest House)\", \"13 Night accommodation in Tibet on sharing basis (Hotels and Guest houses)\", \"Tibet travel Permit and Visa fees\", \"English speaking Tibetan guide for customers formalities\", \"Nepali Supporting Staff (cook, Sherpa, and helper) on a 5:1 basis\", \"Buffet vegetarian meals during Yatra on AP basis (Breakfast, Lunch, and Dinner)\", \"Nepali experienced Team Leader/Guide during Yatra\", \"Supporting truck to carry equipment\", \"Mansarovar and Kailash Yatra Permit fees\", \"Duffel bag for carrying goods during Yatra\", \"Back pack bag for personal items to carry and Cap\", \"Warm down Jacket (refundable)\", \"First aid medical kit bag and Oxygen cylinder\", \"Emergency evacuation management during Yatra\", \"Round trip transportation in Tibet by AC Luxury coach\", \"Kathmandu - Rasuwagadi - Kathmandu Non-AC Vehicle\", \"Arrival and departure transfer with assistance by A/C Vehicle\", \"All sightseeing and excursions as mentioned in the itinerary\", \"Vehicles provided on a point-to-point basis according to the itinerary\", \"Kailash Yatra appreciation certificate\"]','[\"International Airfare – Flights to/from Kathmandu.\", \"Travel Insurance – High-altitude and medical evacuation coverage.\", \"Nepal Visa – Fees for entering Nepal (if applicable).\", \"Personal Expenses – Laundry, drinks, Wi-Fi, and phone calls.\", \"Pony/Porter – Rental of horses or personal porters for the trek.\", \"Staff Tips – Gratuities for guides, drivers, and helpers.\", \"Kathmandu Meals – Lunch and dinner during the Kathmandu stay.\", \"Emergency Costs – Extra expenses due to delays, landslides, or weather.\", \"Medical Bills – Hospitalization or advanced medical treatment.\", \"Single Supplement – Extra cost for private room requests.\"]','[]','[{\"day\": 1, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Arrival in Kathmandu (1,300m)\", \"description\": \"Arrival & Meet: Your spiritual journey begins at Tribhuvan International Airport. Our representative will meet you outside the arrival terminal and transfer you to your hotel. Kathmandu, the capital of Nepal, is a vibrant hub of ancient culture and spirituality.\\n\\nThe Evening Ritual: After settling in, you will attend a comprehensive Yatra Briefing. This session covers vital information on high-altitude health, trekking safety, and the religious protocols of the Kailash circuit. This is also the time to meet your fellow pilgrims and guides.\", \"accommodation\": \"Hotel Mandala Norling Lord Prime (Twin Sharing)\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu Temple Visit & Preparation\", \"description\": \"The Pilgrimage Begins: Spend the day visiting the most sacred sites in the Kathmandu Valley.\\n\\nPashupatinath Temple: Witness the sacred rituals along the Bagmati River at this legendary Shiva temple.\\n\\nBoudhanath Stupa: Walk the kora around one of the world’s largest Buddhist stupas, surrounded by the sound of prayer wheels.\\n\\nJala Narayan: Visit the reclining \\\"Sleeping Vishnu,\\\" a 5th-century masterpiece carved from a single stone.\\n\\nKathmandu Durbar Square: Explore the medieval palace complex and the home of the Living Goddess, Kumari.\\n\\nFinal Preparation: Use the afternoon to double-check your gear. Ensure you have your thermal layers, broken-in trekking boots, and a sturdy daypack.\", \"accommodation\": \"Hotel Mandala Norling Lord Prime (Twin Sharing)\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kathmandu to Kyirung (1,600m)\", \"description\": \"The Himalayan Drive: Leave the city early for a 145 km drive toward the border. The route follows winding mountain roads, passing through terraced fields, deep river gorges, and small Nepali villages.\\n\\nEntry to the Mountains: As you reach Kyirung, you\'ll feel the air cooling and the landscape becoming more rugged. This lower altitude is the perfect first step for your body to begin its long acclimatization process.\", \"accommodation\": \"Basic Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Kyirung to Gyirung County (2,800m)\", \"description\": \"The Frontier: Today marks your official entry into Tibet (China). You will spend time completing immigration and custom formalities on both the Nepal and China sides of the border.\\n\\nDeep Tibet: After crossing, a short 35 km drive brings you to Gyirung County. You will notice a dramatic shift in architecture and culture. Stay hydrated and rest well this evening to help your body adjust to the 2,800m elevation.\", \"accommodation\": \"Basic Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Gyirung to Saga (4,400m)\", \"description\": \"The Plateau Crossing: A scenic 270 km drive that showcases the vastness of the Tibetan Plateau. You will cross high mountain passes and catch glimpses of the snow-capped Himalayan range to the south.\\n\\nThe Brahmaputra: One of the highlights is crossing the legendary Brahmaputra River (Yarlung Tsangpo). By the time you reach Saga, you are in high-altitude territory. Walk slowly and avoid overexertion.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 6, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Saga Acclimatization Day (4,400m)\", \"description\": \"The Rest Strategy: This day is non-negotiable for safety. At 4,400m, your body needs time to produce more red blood cells.\\n\\nExplore: Take a gentle walk through the Saga market. It is a great place to observe the local Tibetan lifestyle or buy any last-minute snacks, dried fruits, or oxygen canisters for the trek ahead.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 7, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Saga to Lake Mansarovar (4,550m)\", \"description\": \"The Holy Sight: A long 470 km drive through the high-altitude desert landscape. As you approach the holy land, you will see the peak of Mt. Kailash in the distance.\\n\\nThe Mind Lake: Reach Lake Mansarovar, the world’s highest body of freshwater. Its turquoise waters are believed to wash away the sins of a lifetime. The serenity of this place, with the Himalayas reflecting in the water, is an unforgettable spiritual experience.\", \"accommodation\": \"Pramath Asram (Dormitory room, Common Bathroom)\"}, {\"day\": 8, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Mansarovar Parikrama & Drive to Darchen (4,600m)\", \"description\": \"The Sacred Circle: Complete the 102 km circuit (Parikrama) of Lake Mansarovar by vehicle. Many pilgrims choose a spot to perform a holy dip and conduct a Puja or Homa (fire ritual) by the lakeshore.\\n\\nBase Camp: Drive 58 km to Darchen, a small settlement located directly at the foot of Mt. Kailash. This is the staging point for the trek. Finalize your daypack for the kora today.\", \"accommodation\": \"Basic hotel (Dormitory room, Common Bathroom)\"}, {\"day\": 9, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Darchen to Diraphuk (4,860m) - Kora Day 1\", \"description\": \"Yamdwar: Start with a short drive to Yamdwar, the \\\"Gate of Salvation.\\\" This is the official starting point of the 52km kora.\\n\\nThe West Face: Begin a 12 km trek through the valley. The trail is relatively gradual and follows the Lha Chu river. You will witness the massive West Face of Mt. Kailash before arriving at Diraphuk, which offers a stunning, unobstructed view of the North Face.\", \"accommodation\": \"Basic Hotel (Dormitory room, Common Bathroom)\"}, {\"day\": 10, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Trek to Charansparsh (5,332m) & Back\", \"description\": \"Touching the Divine: This is an extra-special day for devout pilgrims. You will trek upward toward the very base of the North Face.\\n\\nThe Source: Charansparsh literally means \\\"touching the feet.\\\" According to the Bhagawat Purana, the nearby river is the first source of water on Earth. Here, you can meditate in the literal shadow of the mountain and touch the holy rock of Kailash before returning to Diraphuk.\", \"accommodation\": \"Basic Hotel (Dormitory room, Common Bathroom)\"}, {\"day\": 11, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Diraphuk to Zuthulpuk (4,760m) via Khandesanglam\", \"description\": \"The Inner Path: Today’s trek takes you through Khande Sanglam, a route believed to be where Lord Shiva himself meditates.\\n\\nSacred Landmarks: The trail offers views of Shivasthali (a symbolic site of death and rebirth), Kuber Kund, and Kuber Parbat. If taking the standard Outer Kora, you would cross the Dolma-La Pass (5,630m). Both paths converge at Zuthulpuk, the site of Milarepa’s \\\"Cave of Miracles.\\\"\", \"accommodation\": \"Basic Hotel (Dormitory room, Common Bathroom)\"}, {\"day\": 12, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Zuthulpuk to Darchen & Drive to Saga\", \"description\": \"The Final Miles: A gentle 8 km morning trek marks the final stretch of the kora. The trail levels out as you reach the pickup point.\\n\\nTransition: Rejoin your coach for the drive back to Darchen. After a brief rest and celebration of your trek completion, begin the drive back toward Saga.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 13, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Darchen Acclimatization (Rest Day)\", \"description\": \"Recovery: After the physical exertion of the first kora, this day is for rest.\\n\\nMental Prep: The Inner Kora (Nandi Kora) scheduled for tomorrow is significantly more difficult and requires maximum energy. Use this day for quiet reflection, hydration, and light stretching.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 14, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"The Nandi Kora (Inner Circuit) (Max 5,800m)\", \"description\": \"The Ultimate Test: This is the most challenging day of the journey. A 22 km trek (up to 12 hours) leads you into the Inner Circle of Mt. Kailash.\\n\\nThe Inner Sanctum: Visit Sherlung Gompa, Rishi Cave, and Nandi Parvat. You will trek toward Astapad and the Atmalingam, where you find the sacred Red and White lakes. The high pass between Mt. Kailash and Nandi Parvat is extremely steep and requires determination and physical stamina. Descend following the Kailashi Gange river back to Darchen.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 15, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Darchen to Saga (4,400m)\", \"description\": \"The Homeward Journey: A long 450 km drive back across the plateau. With the spiritual weight of two koras behind you, enjoy the vast, open views of the Tibetan landscape one last time.\", \"accommodation\": \"Hotel Basis (Shared room, Attached Bathroom)\"}, {\"day\": 16, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Saga to Gyirung (2,800m)\", \"description\": \"Descent: Drive 270 km back toward the border. As the altitude drops from 4,400m to 2,800m, you will notice an immediate improvement in your breathing and energy levels. Arrive in Gyirung for your final night in Tibet.\", \"accommodation\": \"Basic Hotel (Shared room, Attached Bathroom)\"}, {\"day\": 17, \"meals\": \"Breakfast, Lunch, Dinner\", \"title\": \"Gyirung to Kathmandu (1,300m)\", \"description\": \"Back to Nepal: Complete your final border formalities and cross back into Nepal.\\n\\nThe Final Drive: A 200 km drive brings you back through the lush greenery and bustling villages of Nepal, arriving in Kathmandu by late evening. Enjoy a long-awaited hot shower and the comforts of the city.\", \"accommodation\": \"Hotel Mandala Norling Lord Prime (Twin Sharing)\"}, {\"day\": 18, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Departure\", \"description\": \"Final Blessing: After breakfast, you will be honored with an Appreciation Certificate to commemorate your successful completion of the Kailash Mansarovar and Inner Kora Yatra.\\n\\nFarewell: Transfer to the international airport for your departure flight, carrying home memories of the world\'s most sacred mountain.\", \"accommodation\": \"\"}]','\"Requires excellent physical condition and mental resilience. Trekkers must handle 6–12 hours of daily walking at altitudes where oxygen is 50% lower than sea level. Previous high-altitude experience (like EBC or Kilimanjaro) is highly recommended for the Inner Kora, which involves steep, rocky slopes and basic mountain scrambling.\"','[\"Kathmandu Valley\", \"Everest Region (En route views)\", \"Mount Kailash North & South Faces\", \"Lake Mansarovar\", \"Tibet\"]','[\"Kailash Outer Kora\", \"Adi Kailash Yatra\", \"Muktinath Pilgrimage\", \"Cultural Tours\", \"Pilgrimage\"]',NULL,NULL,NULL,0,1,'2025-12-18 20:23:38','2025-12-18 20:38:38'),(19,7,'kathmandu-pokhara-muktinath-7n-8d','Kathmandu, Pokhara & Muktinath-7N/8D','Cultural','Pokhara','Outline Itinerary Day 1: Arrival at Kathmandu Day 2: Kathmandu sightseeing Day 3: Drive to Pokhara and sightseeing Day 4: Drive to Muktinath Day 5: Mu...',0.00,NULL,0,0,NULL,'10 days',NULL,'2-12 people','Easy',4.36,179,'March-May, September-November','https://gurutravelsltd.com/uploads/package/images/jomsom-muktinath-.jpg','[\"https://gurutravelsltd.com/uploads/package/images/jomsom-muktinath-.jpg\", \"https://gurutravelsltd.com/uploads/package/images/GetPaidStock.com-667a95ce3515a_qpbgf4D.jpg\", \"https://gurutravelsltd.com/uploads/package/images/boudha_XgZLVZt.jpg\", \"https://gurutravelsltd.com/uploads/package/images/pashni_3fWfIW8.jpg\"]','[]','[\"Airport transfers\", \"Accommodation\", \"Experienced guide\", \"All meals during tour\", \"Permits and fees\", \"Transportation\"]','[\"International flights\", \"Nepal visa fees\", \"Personal expenses\", \"Travel insurance\", \"Tips for guide\"]','[{\"name\": \"Cultural Experience\", \"description\": \"Experience general activities\"}]','[{\"day\": 1, \"title\": \"Day 1\", \"description\": \": Arrival at Kathmandu\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            Meet up at the arrival and heading towards\\nHotel Our office representative will brief you\\nabout the tour activities and transfer to\\nhotel. Overnight at Hotel.\"}, {\"day\": 2, \"title\": \"Day 2\", \"description\": \": Kathmandu sightseeing\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            After Breakfast proceed for the sightseeing\\ntour of Pasuptinath Temple, Bouddhanath\\nStupa After that we will be going to Patan\\ndurbar Square which are the three-world\\nheritage site of Kathmandu. Overnight at\\nKathmandu.\"}, {\"day\": 3, \"title\": \"Day 3\", \"description\": \": Drive to Pokhara and sightseeing\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            After Breakfast, Head towards Kathmandu\\nWhich will take around 7 to 8 hours.\\n(Enroute Manakamana Temple which you\\ncan visit) Overnight at Pokhara.\"}, {\"day\": 4, \"title\": \"Day 4\", \"description\": \": Drive to Muktinath\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            After breakfast we will be heading towards\\nMustang which will take around 7 to 8\\nhours experiencing the breathtaking\\nlandscape and enroute Rupse fall visit and\\nMarpha and at the evening time you can go\\nfor the Muktinath temple aarti.\\nOvernight at Muktinath.\"}, {\"day\": 5, \"title\": \"Day 5\", \"description\": \": Muktinath Visit & Drive back to Kathmandu\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            Early morning visit to Muktinath Temple\\nand Breakfast at hotel and we will be driving\\ntowards pokhara which will take around 7 to\\n8 hours.\"}, {\"day\": 6, \"title\": \"Day 6\", \"description\": \": Pokhara Sightseeing\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            Breakfast at hotel and we will have full day\\nsightseeing of Pumdikot, Bindabasini\\nTemple, Gupteshwor Cave, Davis fall &\\nInternational Mountain Musume.\\nOvernight at Pokhara\"}, {\"day\": 7, \"title\": \"Day 7\", \"description\": \": Drive back to Kathmandu\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            Breakfast at hotel and we will be driving\\ntowards kathmandu which will take around 7\\nto 8 hours and rest free hours for your\\nshopping at vibrant market of kathmandu.\"}, {\"day\": 8, \"title\": \"Day 8\", \"description\": \": Departure\\n                                                        \\n                                                    \\n                                                    \\n                                                        \\n                                                            After Breakfast, as per you flight time 3\\nhours prior Proceed to Kathmandu\\nInternational Airport for flight back to home\\nwith the memories of Nepal.\"}]','\"Basic fitness level sufficient.\"','[]','[]',NULL,NULL,NULL,0,1,'2025-09-19 04:13:16','2025-12-18 04:26:30'),(20,325,'kathmandupokharachitwan-tour-package-','Kathmandu–Pokhara–Chitwan Tour Package ','','','Discover the best of Nepal on this 5 Nights / 6 Days Kathmandu – Pokhara – Chitwan Tour. Explore Kathmandu’s UNESCO heritage sites, enjoy stunning Himalayan views and lakeside serenity in Pokhara, and experience thrilling jungle safaris and rich Tharu culture in Chitwan. A perfect blend of culture, nature, and adventure, ideal for families, couples, and first-time visitors.',0.00,NULL,1,0,NULL,'6 days',NULL,'2-8','',0.00,0,'','/uploads/tours/kathmandupokharachitwan-tour-package-/tour_1766899835744.jpg','[\"/uploads/tours/kathmandupokharachitwan-tour-package-/tour_1766899853187.jpg\", \"/uploads/tours/kathmandupokharachitwan-tour-package-/tour_1766899853409.jpg\", \"/uploads/tours/kathmandupokharachitwan-tour-package-/tour_1766899853439.jpg\"]','[]','[\"Welcome drink at arrival (Non-alcoholic)\", \"02 Night’s accommodation at Kathmandu Hotel on MAP Board basis [B/fast & dinner]\", \"02 Night’s accommodation at Pokhara Hotel on MAP Board basis [B/ fast & Dinner]\", \"01 Night’s accommodation at Chitwan Hotel on AP Board basis [Breakfast/lunch/ Dinner]\", \"01 Liter mineral water per day\", \"Arrival and departure transfer with assistance A/C Vehicle\", \"All sightseeing and excursion as mentioned in the itinerary\", \"All transfer & sightseeing by private Air condition Vehicle\", \"Round trip transportation for Kathmandu – Pokhara – Chitwan – Kathmandu\", \"Vehicle are not to be disposal and are available as per itinerary only (Point to Point basis)\", \"All current Nepal Government taxes\"]','[\"International Airfare\", \"Insurance fee\", \"Monuments entrance fees as applicable & Payable fee on the spot\", \"Manakamana Cable Car tickets\", \"Boat ride fee on Phewa Lake\", \"Personal expenses, tipping and any other services which are not mentioned in the above inclusion\", \"Paragliding / Bungee Jump / Zip- line flyer/ Annapurna Base camp Helicopter Tour/ ultra-light Aircraft / Mountain Flight / River Rafting and Kayaking/ Cycling / Mountain Biking / Golf in Pokhara\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrive at Kathmandu\", \"description\": \"Upon your arrival at Kathmandu Airport, our representative will be there to welcome you and provide assistance after you’ve completed the customs and immigration formalities. You will then be transferred to your hotel for check-in. In your evening, you’ll attend the spiritual Aarti ceremony at the scared Pashupatinath Temple. Overnight stay will be at your hotel Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Drive to Pokhara via Manakamana Cable Car 8-9Hrs)\", \"description\": \"After breakfast, begin your scenic drive to Pokhara, covering a distance of approximately 219 km. En- route enjoy a visit to the sacred Manakama Temple, accessible via an exciting cable car ride offering beautiful views. After the temple visit, continue your journey to Pokhara. Upon arrival, you’ll be transferred to your hotel for check-in. Overnight stay at your hotel in Pokhara.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Sunrise with Pumdikot Temple & Pokhara Sightseeing\", \"description\": \"Early in the morning, drive to Sarangkot hills to witness a breathtaking sunrise and panoramic views of the Himalayan range (weather permitting). Return to the hotel for breakfast. Later, set out for a full day sightseeing tour of Pokhara, including a visit to the Bindavasini temple (dedicated to Goddess Durga), Devi’s waterfall, Gupteshwor Mahadev Cave, and Seti River Gorge. Enjoy a relaxing one-hour boat ride on the serene Phewa Lake, including a visit to the island temple of Tal Barahi. Overnight stay at your hotel in Pokhara.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Pokhara – drive to Chitwan (about 160 km 5-6Hrs drive)\", \"description\": \"After breakfast, depart for Chitwan and enjoy the scenic drive through the countryside. Upon arrival, check in your hotel, where lunch will be served. In the afternoon, explore a traditional Tharu village to learn about the local culture and way of life. In the evening, witness a beautiful sunset followed by a lively Tharu cultural performance featuring the traditional stick dance. Overnight in Chitwan.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Chitwan safari drive back to Katmandu\", \"description\": \"After breakfast, set out for an exciting Jeep Safari in Chitwan National Park, where you’ll have the chance to spot diverse wildlife in their natural habitat. After the safari, return to the hotel and prepare for your drive to Kathmandu. Upon arrival in Kathmandu, enjoy some free time for shopping at the vibrant Thamel Market at your own pace. Later, check in to your hotel. Overnight stay at your hotel in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Sightseeing and departure\", \"description\": \"After breakfast sightseeing of Kathmandu Valley including Boudhanath Stupa, Jala Temple (Sleeping Vishnu), Swyambhunath Stupa (Monkey temple) and Kathmandu Durbar Square (Living God Kumari). Then you will be transferred to the Airport in time.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Kathmandu\", \"Pokhara\", \"Chitwan\"]','[\"City Tours\", \"Jungle Safari\", \"Cultural Tours\"]',NULL,NULL,NULL,0,1,'2025-12-28 05:30:56','2025-12-28 05:30:56'),(21,331,'langtang-gosaikunda-lake-trek-7-days-sacred-himalayan-journey','Langtang Gosaikunda Lake Trek – 7 Days Sacred Himalayan Journey','','','The Langtang Gosaikunda Lake Trek is a perfect blend of spiritual significance, alpine adventure, and raw Himalayan beauty. This 7-day journey takes you from the vibrant streets of Kathmandu to the sacred high-altitude lakes of Gosaikunda (4,380m), revered by both Hindus and Buddhists.\n\nStarting with a scenic drive to Dhunche, the trek gradually ascends through lush pine forests, Tamang villages, cascading waterfalls, and dramatic mountain landscapes. Along the trail, you’ll experience the warm hospitality of local communities, explore ancient monasteries like Sing Gompa (Chandanbari), and witness breathtaking views of Langtang Lirung, Ganesh Himal, Manaslu, and surrounding peaks.\n\nThe highlight of the trek is the arrival at Gosaikunda Lake, a sacred alpine lake believed to have been created by Lord Shiva. Surrounded by rugged Himalayan terrain and serene glacial waters, the area offers a deeply peaceful and spiritual experience. The return journey follows the same scenic route back to Dhunche before driving to Kathmandu, leaving you with unforgettable memories of Nepal’s natural and cultural richness.\n\nThis trek is ideal for adventure seekers, spiritual travelers, and nature lovers looking for a moderate Himalayan trek with deep cultural meaning.',0.00,NULL,1,0,NULL,'7 days',NULL,'6-10','',0.00,0,'March, April, May, September, October, November','/uploads/tours/langtang-gosaikunda-lake-trek-7-days-sacred-himalayan-journey/tour_1769941793905.jpg','[\"/uploads/tours/langtang-gosaikunda-lake-trek-7-days-sacred-himalayan-journey/tour_1769942875033.jpg\", \"/uploads/tours/langtang-gosaikunda-lake-trek-7-days-sacred-himalayan-journey/tour_1769942875040.jpg\", \"/uploads/tours/langtang-gosaikunda-lake-trek-7-days-sacred-himalayan-journey/tour_1769942875066.jpg\"]','[\"Visit the sacred alpine lakes of Gosaikunda (4,380m), revered by Hindus and Buddhists\", \"Scenic drive through the Trishuli River valley and traditional hill villages\", \"Trek through pine, rhododendron, and alpine forests\", \"Experience Tamang culture and Tibetan-influenced mountain lifestyle\", \"Explore Sing Gompa (Chandanbari Monastery) and famous yak cheese factory\", \"Comfortable stays in teahouses and a 3-star hotel in Kathmandu\", \"Moderate trek suitable for both adventure seekers and spiritual travelers\"]','[\"Airport pickup and drop-off by private vehicle\", \"2 nights accommodation in a 3-star hotel in Thamel (bed & breakfast)\", \"All ground transportation as per itinerary (Kathmandu–Dhunche–Kathmandu)\", \"Accommodation in well-maintained teahouses/lodges during trekking days\", \"Experienced, licensed English-speaking trekking guide\", \"Porter service (as per group size)\", \"Trekking permits and necessary government taxes\", \"Langtang National Park entry permit\", \"TIMS (Trekkers’ Information Management System) card\", \"Comprehensive trek briefing before departure\"]','[\"International airfare\", \"Nepal entry visa fees\", \"Travel and personal insurance (mandatory for trekking)\", \"Personal trekking equipment and gear\", \"Hot showers, Wi-Fi, charging, and bottled drinks during the trek\", \"Alcoholic and non-alcoholic beverages\", \"Personal expenses (laundry, tips, snacks, etc.)\", \"Extra accommodation or meals due to early arrival or late departure\", \"Any costs arising from unforeseen circumstances (weather, landslides, flight delays)\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival in Kathmandu (1,400m)\", \"description\": \"Upon arrival at Tribhuvan International Airport, our representative will warmly welcome you and transfer you to your hotel. After check-in, you can relax or explore nearby streets filled with cafes, shops, and cultural landmarks. \", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast, Lunch & Dinner\", \"title\": \"Drive from Kathmandu to Dhunche (1,960m)\", \"description\": \"After breakfast, you’ll drive to Dhunche, the gateway to Langtang National Park. The scenic journey passes through terraced farmlands, forests, rivers, and rural settlements along the Trishuli River. Upon arrival, explore the village and interact with local Tamang people.\\n\\nDrive Duration: 5–6 hours\", \"accommodation\": \"Tea House\"}, {\"day\": 3, \"meals\": \"Breakfast, Lunch & Dinner\", \"title\": \"Trek from Dhunche to Chandanbari (Sing Gompa) – 3,330m\", \"description\": \"Today’s trek begins with a gradual ascent through pine forests and scenic trails. Passing through Ghatte Khola and Deurali, you’ll enjoy peaceful surroundings and fresh mountain air. Chandanbari, also known as Sing Gompa, is famous for its monastery and yak cheese factory.\\n\\nTrek Duration: 5–6 hours\", \"accommodation\": \"Tea House\"}, {\"day\": 4, \"meals\": \"Breakfast, Lunch & Dinner\", \"title\": \"Trek from Chandanbari to Gosaikunda (4,380m)\", \"description\": \"This is the most rewarding day of the trek. The trail ascends through rugged terrain with breathtaking views of Himalayan peaks. Along the way, you’ll pass Cholangpati, Lauribina, and the sacred Bhairav Kunda and Saraswati Kunda before reaching Gosaikunda Lake. Spend time exploring the surrounding lakes and soaking in the spiritual atmosphere.\\n\\nTrek Duration: 5–6 hours\", \"accommodation\": \"Tea House\"}, {\"day\": 5, \"meals\": \"Breakfast, Lunch & Dinner\", \"title\": \"Trek from Gosaikunda to Dhunche\", \"description\": \"After sunrise views over Gosaikunda, you’ll begin your descent back to Dhunche via Lauribina and Chandanbari. The downhill trek offers a different perspective of the landscapes and increases chances of spotting wildlife such as Himalayan birds and, if lucky, the rare red panda.\\n\\nTrek Duration: 7–8 hours\", \"accommodation\": \"Tea House\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Drive from Dhunche to Kathmandu\", \"description\": \"Following breakfast, you’ll drive back to Kathmandu, enjoying scenic views of hills, rivers, and countryside along the way. Upon arrival, check in to your hotel and enjoy a free evening for shopping or relaxation.\\n\\nDrive Duration: 5–6 hours\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 7, \"meals\": \"Breakfast\", \"title\": \"Final Departure\", \"description\": \"Our team will transfer you to the airport for your onward journey. If you wish to extend your stay or add other tours, we’ll be happy to arrange it for you.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Gosaikunda Trek\"]','[\"Mountaineering\", \"Adventure Sports\"]',NULL,NULL,NULL,0,1,'2026-02-01 10:58:08','2026-02-01 11:03:03'),(22,309,'muktinath-yatra-6n-7d','Muktinath Yatra - 6 Nights 7 Days by Flight','Pilgrimage','Nepal','Embark on a sacred pilgrimage to Muktinath Temple, one of the most revered Hindu and Buddhist temples in the Himalayas. Located at 3,710 meters in the Mustang district, this holy shrine is believed to grant salvation (moksha) to devotees. The temple houses 108 water spouts and an eternal flame, making it a unique spiritual destination. This comfortable journey by flight eliminates the need for long drives, allowing more time for spiritual contemplation and exploration of the mystical Mustang region.',0.00,NULL,0,0,NULL,'7 days',NULL,'2-15 people','Moderate',4.60,134,'March-November','https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Sacred Muktinath Temple darshan\", \"108 holy water spouts\", \"Eternal flame (Jwala Mai)\", \"Spectacular Himalayan views\", \"Jomsom and Kagbeni exploration\", \"Tibetan Buddhist culture\", \"Scenic mountain flights\"]','[\"Domestic flights (Kathmandu-Jomsom-Kathmandu)\", \"Hotel accommodation\", \"Daily breakfast\", \"All transfers and transportation\", \"Professional guide\", \"Temple entrance fees\", \"Muktinath darshan arrangements\"]','[\"International flights\", \"Lunch and dinner\", \"Personal expenses\", \"Travel insurance\", \"Tips for guide and staff\", \"Pony/horse rides (optional)\", \"Additional temple donations\"]','[{\"name\": \"Temple Pilgrimage\", \"description\": \"Sacred darshan at Muktinath Temple and spiritual ceremonies\"}, {\"name\": \"Cultural Exploration\", \"description\": \"Explore Tibetan Buddhist culture and ancient monasteries\"}, {\"name\": \"Mountain Views\", \"description\": \"Spectacular views of Annapurna and Dhaulagiri ranges\"}, {\"name\": \"Village Tours\", \"description\": \"Visit traditional Thakali and Tibetan villages\"}]','[{\"day\": 1, \"title\": \"Arrival in Kathmandu\", \"description\": \"Welcome to Nepal! Upon arrival at Tribhuvan International Airport, our representative will receive you with traditional Khada and transfer you to your hotel in Kathmandu. After check-in and refreshment, attend a briefing about your sacred Muktinath Yatra. Visit Pashupatinath Temple in the evening for darshan and to witness the mesmerizing Ganga Aarti ceremony on the banks of the holy Bagmati River. This spiritual preparation sets the tone for your pilgrimage journey. Return to hotel for overnight stay.\"}, {\"day\": 2, \"title\": \"Fly to Jomsom & Drive to Muktinath\", \"description\": \"Early morning flight to Jomsom (2,720m), offering spectacular aerial views of the Annapurna and Dhaulagiri mountain ranges. The 20-minute scenic flight is an experience in itself, flying between towering peaks. Upon landing at Jomsom airport, drive to Muktinath Temple (3,710m) via the ancient trade route. The journey takes you through the mystical landscape of Mustang with its unique desert-like terrain. Check into hotel near Muktinath Temple and acclimatize to the altitude. Evening visit to Muktinath Temple for initial darshan and prayers.\"}, {\"day\": 3, \"title\": \"Muktinath Temple Darshan & Exploration\", \"description\": \"Early morning visit to the sacred Muktinath Temple for the main darshan ceremony. This revered temple is significant for both Hindus and Buddhists, housing the eternal flame (Jwala Mai) that burns continuously from natural gas. Take a purifying bath under the 108 water spouts, each representing a sacred stream. The temple complex includes the main Vishnu temple, Buddhist gompa, and various shrines. Spend time in meditation and prayer. Afternoon exploration of the surrounding area including Jwala Mai Temple where natural gas creates an eternal flame. Experience the spiritual energy of this high-altitude sacred site.\"}, {\"day\": 4, \"title\": \"Muktinath to Jomsom via Kagbeni\", \"description\": \"After morning prayers at Muktinath Temple, drive to the ancient village of Kagbeni, known as the \'Gateway to Upper Mustang.\' This medieval village with its narrow alleys, ancient monastery, and traditional Tibetan architecture offers a glimpse into the region\'s rich cultural heritage. Explore the Red Gompa (monastery) and interact with local Tibetan Buddhist communities. Continue to Jomsom, the administrative center of Mustang district. Visit the local market and experience the unique Thakali culture. Jomsom is famous for its apple orchards and strong afternoon winds. Overnight in Jomsom.\"}, {\"day\": 5, \"title\": \"Jomsom Exploration & Marpha Village\", \"description\": \"Full day exploration of the Jomsom area. Visit Marpha village, famous for its apple brandy, dried fruits, and traditional white-washed houses. This picturesque village is known for its cleanliness and well-preserved Thakali culture. Tour local distilleries and taste the famous apple brandy. Visit the ancient Marpha Gompa and learn about Tibetan Buddhism. Return to Jomsom and explore the local bazaar. Visit Jomsom Gompa and interact with monks. The afternoon brings strong winds characteristic of this region, creating a unique natural phenomenon. Enjoy spectacular sunset views over the Himalayas.\"}, {\"day\": 6, \"title\": \"Fly to Kathmandu\", \"description\": \"Morning flight from Jomsom to Kathmandu, weather permitting. The return flight offers another opportunity to witness the magnificent Himalayan panorama from a different perspective. Upon arrival in Kathmandu, transfer to your hotel and freshen up. Afternoon visit to Swayambhunath Stupa (Monkey Temple) for thanksgiving prayers and to complete your spiritual journey. This ancient Buddhist stupa offers panoramic views of Kathmandu Valley. Evening free for shopping in Thamel or relaxation. Farewell dinner featuring traditional Nepali cuisine with cultural performances.\"}, {\"day\": 7, \"title\": \"Departure\", \"description\": \"After breakfast, enjoy some free time for final prayers, shopping, or relaxation. Visit local temples if time permits for final blessings. Our representative will assist with airport transfer according to your flight schedule. Depart with the sacred blessings of Muktinath and unforgettable memories of this spiritual journey. The pilgrimage to Muktinath is believed to cleanse sins and grant moksha (salvation), making this a truly transformative experience.\"}]','\"Moderate fitness level required due to high altitude. Basic walking ability needed for temple visits.\"','[]','[]',NULL,NULL,NULL,1,1,'2024-12-30 10:00:00','2025-12-18 04:22:52'),(23,310,'nepal-heritage-tour-5n-6d','Nepal Heritage Tour - 5 Nights 6 Days','Cultural','Nepal','Immerse yourself in Nepal\'s rich cultural heritage with this comprehensive tour covering UNESCO World Heritage sites in Kathmandu Valley. Explore ancient temples, medieval palaces, and traditional architecture that showcase Nepal\'s glorious past. This cultural journey takes you through the living museums of Kathmandu, Patan, and Bhaktapur, where centuries-old traditions continue to thrive. Experience the spiritual essence of Nepal through its sacred sites, vibrant festivals, and warm hospitality of the Newar people.',0.00,NULL,0,0,NULL,'6 days',NULL,'2-20 people','Easy',4.50,198,'September-May','https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','[\"https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1605640840605-14ac1855827b?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\", \"https://images.unsplash.com/photo-1578662996442-48f60103fc96?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]','[\"Seven UNESCO World Heritage sites\", \"Kathmandu Durbar Square exploration\", \"Patan\'s ancient art and architecture\", \"Bhaktapur medieval city tour\", \"Swayambhunath and Boudhanath stupas\", \"Pashupatinath Temple ceremonies\", \"Traditional Newari culture experience\"]','[\"Hotel accommodation (3-4 star)\", \"Daily breakfast\", \"All transfers and transportation\", \"Professional cultural guide\", \"All entrance fees to heritage sites\", \"Cultural performances\", \"Airport transfers\"]','[\"International flights\", \"Lunch and dinner\", \"Personal expenses\", \"Travel insurance\", \"Tips for guide and staff\", \"Shopping expenses\", \"Additional activities\"]','[{\"name\": \"Heritage Site Tours\", \"description\": \"Explore UNESCO World Heritage sites with expert cultural guides\"}, {\"name\": \"Architecture Appreciation\", \"description\": \"Study ancient Newari architecture and wood carving techniques\"}, {\"name\": \"Cultural Immersion\", \"description\": \"Experience traditional festivals, ceremonies, and local customs\"}, {\"name\": \"Art and Craft\", \"description\": \"Visit traditional workshops and observe master craftsmen at work\"}]','[{\"day\": 1, \"title\": \"Arrival in Kathmandu\", \"description\": \"Welcome to the cultural heart of Nepal! Upon arrival at Tribhuvan International Airport, our representative will greet you with traditional Khada and transfer you to your heritage hotel in Kathmandu. After check-in and refreshment, begin your cultural journey with a visit to Kathmandu Durbar Square, the former royal palace complex. Explore the ancient courtyards, intricate wood carvings, and meet the Living Goddess Kumari if she appears at her window. Visit the Hanuman Dhoka Palace and learn about Nepal\'s royal history. Evening welcome dinner with traditional Newari cuisine and cultural performances.\"}, {\"day\": 2, \"title\": \"Swayambhunath & Patan Heritage Tour\", \"description\": \"After breakfast, visit Swayambhunath Stupa (Monkey Temple), perched atop a hill overlooking Kathmandu Valley. This ancient Buddhist stupa is over 2,000 years old and offers panoramic views of the valley. Observe the harmonious coexistence of Hindu and Buddhist traditions. Drive to Patan, also known as Lalitpur (City of Beauty), famous for its exquisite Newari architecture and metalwork. Explore Patan Durbar Square with its stunning temples, courtyards, and the former royal palace. Visit the Golden Temple (Hiranya Varna Mahavihar) and observe traditional Buddhist rituals. Tour local workshops to see master craftsmen creating traditional metalwork and wood carvings.\"}, {\"day\": 3, \"title\": \"Bhaktapur Medieval City Tour\", \"description\": \"Full day exploration of Bhaktapur, the best-preserved medieval city in Nepal. This living museum showcases authentic Newari culture and architecture. Begin at Bhaktapur Durbar Square with its 55-window palace, Vatsala Temple, and the famous Nyatapola Temple, a five-story pagoda representing the five elements. Visit Pottery Square to watch traditional pottery making using ancient techniques. Explore Dattatreya Square with its medieval temples and traditional houses. Experience local life by walking through narrow alleys, observing daily rituals, and tasting traditional Newari snacks like \'juju dhau\' (king curd) and \'bara\' (lentil pancakes). Return to Kathmandu in the evening.\"}, {\"day\": 4, \"title\": \"Pashupatinath & Boudhanath Exploration\", \"description\": \"Begin with an early morning visit to Pashupatinath Temple, the most sacred Hindu temple in Nepal dedicated to Lord Shiva. Observe morning rituals, cremation ceremonies on the ghats, and interact with colorful sadhus (holy men). This UNESCO World Heritage site provides deep insights into Hindu traditions and the cycle of life and death. Continue to Boudhanath Stupa, one of the largest Buddhist stupas in the world and a major pilgrimage site for Tibetan Buddhists. Walk around the stupa with pilgrims, spin prayer wheels, and visit surrounding monasteries. Experience the peaceful atmosphere and observe monks in prayer. Evening visit to a traditional Tibetan monastery for meditation session.\"}, {\"day\": 5, \"title\": \"Changu Narayan & Cultural Workshops\", \"description\": \"Visit Changu Narayan Temple, the oldest Hindu temple in Nepal dating back to the 4th century. This UNESCO World Heritage site is dedicated to Lord Vishnu and features the finest examples of stone, wood, and metal craft. The temple offers spectacular views of the Himalayas and surrounding countryside. Afternoon visit to traditional craft workshops in Thimi, famous for pottery and paper-making. Participate in hands-on activities like pottery making, traditional paper production from lokta bark, and observe mask-making techniques. Visit a traditional Newari house to experience authentic local hospitality and learn about traditional architecture and lifestyle.\"}, {\"day\": 6, \"title\": \"Final Heritage Sites & Departure\", \"description\": \"Final morning exploration of any missed heritage sites or revisit your favorite locations for photography and deeper appreciation. Visit the Garden of Dreams, a neo-classical garden that provides a peaceful retreat in the heart of Kathmandu. Last-minute shopping in Thamel for traditional handicrafts, thangka paintings, singing bowls, and souvenirs. Our representative will assist with airport transfer according to your flight schedule. Depart with a deep appreciation of Nepal\'s rich cultural heritage and unforgettable memories of ancient traditions that continue to thrive in modern times.\"}]','\"Basic fitness level required for walking and climbing temple stairs. Suitable for all age groups.\"','[]','[]',NULL,NULL,NULL,0,1,'2024-12-30 10:00:00','2025-12-18 04:23:27'),(24,324,'nepal-tour-3-nights-4-days','Nepal Tour 3 Nights 4 Days','','','This 4-day journey offers a serene and enriching exploration of Kathmandu’s spiritual heart and cultural treasures. Beginning with a warm welcome in the capital, the tour sets a devotional tone with an evening aarti at the sacred Pashupatinath Temple. Over the next days, travelers uncover the essence of the Kathmandu Valley through visits to revered UNESCO World Heritage Sites, including Swayambhunath Stupa, Boudhanath Stupa, Kathmandu Durbar Square, and the holy Jal Narayan (Sleeping Vishnu) Temple.\n\nThe experience is enhanced by a scenic cable car ride to Chandragiri Hills, where panoramic valley views and a visit to Baleshwar Mahadev Temple provide moments of peace and reflection. A cultural visit to Patan Durbar Square showcases the artistic brilliance of Newari civilization. Designed for those seeking spirituality, heritage, and gentle exploration, this tour delivers a meaningful and memorable Kathmandu escape.\n',0.00,NULL,1,0,NULL,'4 days',NULL,'2-8','',0.00,0,'','/uploads/tours/nepal-tour-3-nights-4-days/tour_1766568836156.jpg','[\"/uploads/tours/nepal-tour-3-nights-4-days/tour_1766569750759.webp\", \"/uploads/tours/nepal-tour-3-nights-4-days/tour_1766569752500.jpg\"]','[\"Evening aarti at Pashupatinath Temple\", \"Visit Swayambhunath Stupa (Monkey Temple)\", \"Explore Boudhanath Stupa (UNESCO World Heritage Site)\", \"Sightseeing at Kathmandu Durbar Square and Jal Narayan Temple\", \"Scenic cable car ride to Chandragiri Hills\", \"Visit Baleshwar Mahadev Temple\", \"Explore Patan Durbar Square and Krishna Mandir\", \"Panoramic views of the Kathmandu Valley and Himalayas\"]','[\"Traditional welcome drink on Arrival (Non-alcoholic)\", \"Assistant Guide in arrival and departure / Hotel\", \"03 Night’s accommodation on double sharing basis\", \"English / Hindi speaking tour guide for sightseeing\", \"01-liter mineral water per day during trip\", \"Arrival and departure transfer and sightseeing by A/C Vehicle\", \"All vehicle parking fees at the attractions.\", \"Vehicles are not to be at disposal and are available as per itinerary only (point to point basis)\", \"All current Nepal government taxes.\"]','[\"International airfare and Nepal visa fees\", \"Travel insurance\", \"Lunch and dinner (unless mentioned)\", \"Personal expenses (drinks, laundry, tips, phone calls, souvenirs)\", \"Entrance fees not mentioned in the itinerary\", \"Any service or activity not included in the inclusions\", \"Cable car ride at Chandragiri Hills Ticket\", \"Monuments entrances fees\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrive in Kathmandu\", \"description\": \"Upon Arrival in Kathmandu Airport, you Will be greeted and assisted by our representative after completing your custom formalities, transfer to the hotel for check-in. In evening attend Aarti at Pashupatinath temple later drive back to hotel. Overnight at Kathmandu hotel.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast \", \"title\": \"Kathmandu city Sightseeing\", \"description\": \"After breakfast Kathmandu City sightseeing tour, visit Swoyambhunath Stupa (World heritage site), Jala Narayan Temple (Sleeping Vishnu), Kathmandu Durbar Square (Living God Kumari) & Boudhanath Stupa (world Heritage site) Later drive back to hotel. Overnight is at Hotel in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Kathmandu – drive to Chandragiri Hills via Cable Car\", \"description\": \"After breakfast drive to Chandragiri hill continue take cable car ride (2-3 Hours) darshan of Baleshwar Mahadev Temple afternoon drive to Patan Durbar Square (Krishna Mandir) later drive back to hotel. Overnight is at Hotel in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Departure transfer\", \"description\": \"After breakfast, the morning will be comparatively free and closer to the time of your flight, you will be transferred to the airport to board your flight for onward journey.\", \"accommodation\": \"3-Star Hotel\"}]','\"\"','[\"Kathmandu\"]','[\"City Tours\", \"Cultural Tours\"]',NULL,NULL,NULL,0,1,'2025-12-24 09:49:19','2025-12-24 09:49:19'),(25,327,'nepal-tour-4nights-5days-','Nepal Tour 4Nights 5Days ','','','Discover the cultural heart and scenic beauty of Nepal with this Kathmandu & Nagarkot Tour. Explore Kathmandu’s UNESCO World Heritage Sites, ancient temples, and vibrant local markets that reflect the city’s rich history and spiritual traditions. From sacred shrines to historic palace squares, Kathmandu offers a fascinating blend of culture and heritage.\nEscape to Nagarkot, a peaceful hill station renowned for its breathtaking sunrise and panoramic Himalayan views. Surrounded by lush hills and fresh mountain air, Nagarkot is the perfect retreat for relaxation and photography, offering unforgettable vistas of snow-capped peaks in a serene natural setting.',0.00,NULL,1,0,NULL,'5 days',NULL,'2-8 people','',0.00,0,'','/uploads/tours/nepal-tour-4nights-5days-/tour_1766900758861.jpg','[]','[]','[]','[]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrive in Kathmandu\", \"description\": \"Arrive at Tribhuvan International Airport and transfer to your hotel. In the evening, visit the famous Pashupatinath temple to attend the beautiful evening aarti on the banks of the Bagmati River. Overnight stay in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Kathmandu-Drive to Bhaktapur-Doleshwar-Saga\", \"description\": \"After breakfast, drive to Bhaktapur, Known for its medieval charm and Bhaktapur Durbar Square. Continue to Doleshwar Temple, a historic Shiva temple, and then to Sanga, home to Kailashnath Mahadev Statue, one of the tallest Shiva statues in the world. Return to Kathmandu in the evening. Overnight stay in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Kathmandu Half day Sightseeing-Drive to Nagarkot\", \"description\": \"After breakfast, enjoy half day sightseeing in Kathmandu, visit Swoyambhunath (Monkey Temple), Kathmandu Durbar Square (Living God Kumari). Drive to Nagarkot, a hills station famous for panoramic views of the Himalayans. Enjoy the evening watching the sunset over the mountains. Overnight stay in Nagarkot.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Nagarkot Explore -Drive back to Kathmandu\", \"description\": \"Wake up early to witness the spectacular sunrise over the Himalayas. After breakfast, explore the surrounding of the Nagarkot with short walks or nature trails. Later in the day, drive to Kathmandu. Overnight stay in Kathmandu.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Kathmandu departure Transfer\", \"description\": \"After breakfast, check out and transfer to Tribhuvan International Airport for your departure flight.\", \"accommodation\": \"3-Star Hotel\"}]','\"\"','[\"Kathmandu\", \"Nagarkot\"]','[\"Cultural Tours\", \"City Tours\"]',NULL,NULL,NULL,0,1,'2025-12-28 05:46:09','2025-12-28 05:46:09'),(26,319,'thailand-escape-bangkok-temples-pattaya-beaches-','Thailand Escape: Bangkok Temples, Pattaya Beaches ','','','Enjoy a perfect 5-day Bangkok & Pattaya getaway combining tropical beaches, cultural highlights, and city exploration. Relax in Pattaya, explore vibrant nightlife, and experience the beauty of Coral Island (Koh Larn) with crystal-clear waters and optional water activities. Discover Bangkok’s iconic temples, enjoy world-class shopping, local markets, and rooftop city views. This tour offers a memorable blend of relaxation, culture, and adventure, leaving you with lasting memories of Thailand’s charm and hospitality.',0.00,NULL,1,0,NULL,'5 days',NULL,'2-8','',0.00,0,'','/uploads/tours/thailand-escape-bangkok-temples-pattaya-beaches-/tour_1766378616377.webp','[\"/uploads/tours/thailand-escape-bangkok-temples-pattaya-beaches-/tour_1766378583299.jpg\", \"/uploads/tours/thailand-escape-bangkok-temples-pattaya-beaches-/tour_1766378583307.jpg\"]','[\"Arrival in Bangkok & transfer to Pattaya\", \"Leisure time at Pattaya Beach & optional Walking Street visit\", \"Coral Island (Koh Larn) speedboat tour with lunch\", \"Optional water activities in crystal-clear waters\", \"Guided Bangkok city tour\", \"Visit Golden Buddha (Wat Traimit) & Reclining Buddha (Wat Pho)\", \"Free day for shopping & exploration\", \"Comfortable airport transfers\"]','[\"2 nights stay in Bangkok \", \"2 nights stay in Pattaya \", \"Daily Breakfast as per Itinerary\", \"Guided Bangkok city & temple tour with iconic landmarks\", \"Excursion to Coral Island (Koh Larn) with speedboat transfer\", \"All sightseeing tours and transfers in air-conditioned comfort\", \"Thailand visa fees \", \"Round-trip international airfare\", \"Private airport transfers in Thailand\", \"Leisure time at Pattaya Beach\", \"Optional Walking Street nightlife experience\", \"Travel support and assistance throughout the tour\", \"Personalized itinerary planning and guidance by Zeo Tourism\"]','[\"Meals, beverages, snacks, and refreshments not explicitly mentioned in the Package Includes section, including minibar consumption and specialty dining experiences\", \"Costs related to optional tours, experiences, adventure activities, or any services arranged independently by the guest during the tour\", \"Any personal transfers, private transportation arrangements, extended waiting or halting charges, or deviations from the scheduled itinerary\", \"Entrance fees, camera or video charges, and special permits unless clearly stated as included\", \"Any expenses arising from unforeseen circumstances such as flight delays, natural events, weather conditions, government regulations, or factors beyond the control of the tour operator\", \"Any service, activity, or expense not specifically listed under the Package Includes, whether of personal preference or incidental nature\", \"All expenses of a personal nature, including but not limited to laundry services, telephone and internet usage, room service, gratuities, shopping, and any other incidental costs incurred during the journey\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival in Bangkok | Transfer to Pattaya\", \"description\": \"Upon arrival at Bangkok Airport, you will be warmly welcomed and guided toward your vehicle. From here, you begin your scenic journey to Pattaya, a vibrant coastal city located about two hours from Bangkok. Along the way, you may catch glimpses of Thai countryside, bustling roadways, and the gradual shift from cityscapes to ocean views.\\nOnce you reach Pattaya, you check into your hotel and unwind after your travels. The afternoon is at leisure, perfect for relaxing or strolling along the beach. As the sun sets, the city begins to glow with lights. You may choose to explore the buzzing nightlife of walking street, or simply enjoy a quiet dinner by the seaside.\", \"accommodation\": \"3-Star Hotel  \"}, {\"day\": 2, \"meals\": \"Breakfast & Lunch\", \"title\": \"Half – day Coral Island Tour with Lunch\", \"description\": \"After breakfast, your day begin with an exciting speedboat ride to Coral Island also known as Koh Larn, one of the most beautiful islands near Pattaya. The journey over crystal-clear water is exhilarating and soon you are greeted by soft white sand, gentle waves and clear blue skies.\\n\\nAt the island, you can relax on the beach or take part in optional water activities like parasailing, snorkeling or jet skiing. The underwater world here is captivating, with coral reefs and colorful marine life visible even in shallow water. A delicious Thai lunch is served at a beachside restaurant, offering local flavors with a view of the sea.\\nYou return to Pattaya in the afternoon with time to relax or explore more on your own.\", \"accommodation\": \"3-Star Hotel \"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Transfer to Bangkok and Half- day Bangkok city tour\", \"description\": \"After breakfast and check-out, you travel back to Bangkok. Upon arrival, your half day city tour begins, taking you through some od the city’s most iconic and sacred sites.\\nYou visit Wat Traimit, home to the Golden Buddha- a solid gold statue that gleams under temple\\nlights. Next is Wat Pho, where the massive Reclining Buddha lies in serene majesty, and the temple grounds are filled with chedis and intricate murals. Optionally, you may also stop by Wat Arun or the Grand Place area for a photo stop or short walk.\\n\\nAs you make your way through the city, you pass vibrant neighborhoods, royal ground and riverside temple. After the tour, you check in at Bangkok hotel and can spend the evening as you like perhaps shopping, enjoy Thai street food, or relaxing with spa treatment.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Free Day for shopping and exploring the city\", \"description\": \"Today is you to explore Bangkok at your own pace. This dynamic city offers something for every kind of traveler. You might begin your day with visit to Siam Paragon or MBK Center two of the city’s largest shopping malls filled with fashion, electronics and local brands.\\nIf you are looking for something more traditional you could explore the Chatuchak Weekend Market or take a boat to a nearby floating market where wooden boats glide by, piled high with tropical fruits, Thai snacks, and handicrafts.\\nBangkok’s culture side is also worth exploring – art galleries, traditional Thai houses, and tranquil parks are scattered throughout the city. In the evening, consider visiting a sky bar like Mahanakhon Skywalk, where panoramic views of Bangkok stretch far into the distance under a glowing sunset.\", \"accommodation\": \"3-Star Hotel \"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Transfer to Bangkok airport for Departure\", \"description\": \"After breakfast, it’s time to check out. Depending on your flight time, you might squeeze in some last-minute shopping or enjoy a quiet morning coffee while watching the city stir awake. Your private transfer will take you to the airport, concluding your memorable journey through Thailand.\\nAs you head home, you carry with memories of serene temple, tropical islands, flavorful cuisine, and the warm hospitality that Thailand is known for.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Thailand\"]','[\"City Tours\", \"Luxury Experiences\"]',NULL,NULL,NULL,1,1,'2025-12-22 04:43:39','2025-12-22 04:48:48'),(27,320,'thailand-island-city-experience-8-days-of-wonder','Thailand Island & City Experience – 8 Days of Wonder','','','Discover the best of Thailand with a perfectly balanced journey through vibrant cities and tropical islands. Begin in Bangkok, exploring its lively atmosphere and iconic attractions before flying to Phuket, Thailand’s famous beach paradise. Enjoy a full-day Phi Phi Island tour with crystal-clear waters, stunning limestone cliffs, and unforgettable island scenery. Continue to Krabi for an exciting Four Island tour, featuring beautiful beaches and snorkeling spots. Return to Bangkok for a memorable evening dinner cruise and a fun-filled visit to Safari World and Marine Park. This tour offers the ideal mix of relaxation, adventure, and cultural experiences.',0.00,NULL,1,0,NULL,'8 days',NULL,'2-8','',0.00,0,'','/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394317694.jpg','[\"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394297605.jpg\", \"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394297712.jpg\", \"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394298069.avif\", \"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394298104.webp\", \"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394298782.webp\", \"/uploads/tours/thailand-island-city-experience-8-days-of-wonder/tour_1766394299751.jpg\"]','[\"Arrival in vibrant Bangkok, Thailand’s cultural and entertainment hub\", \"Scenic flight to Phuket, the island paradise of beaches and nightlife\", \"Full-day Phi Phi Island tour with lunch and crystal-clear waters\", \"Comfortable transfer from Phuket to Krabi\", \"Four Island tour in Krabi featuring snorkeling and stunning beaches\", \"Return to Bangkok with a romantic evening dinner cruise\", \"Fun and exciting visit to Safari World & Marine Park\", \"Perfect blend of city life, islands, nature, and family-friendly attractions\"]','[\"Airport pick-up and drop-off as per itinerary\", \"Domestic flights: Bangkok–Phuket and Krabi–Bangkok\", \"Hotel accommodation in Bangkok, Phuket, and Krabi with daily breakfast\", \"Full-day Phi Phi Island tour with lunch on shared basis\", \"Full-day Four Island tour in Krabi with lunch on shared basis\", \"Evening dinner cruise in Bangkok\", \"Safari World & Marine Park entrance tickets\", \"All intercity transfers by air-conditioned vehicle\", \"Services of a professional tour coordinator/driver\", \"All applicable taxes and service charges\", \"International Fare\", \"Thailand Visa fee\"]','[\"Personal expenses such as laundry, phone calls, minibar, and tips\", \"Meals and beverages not mentioned in the itinerary\", \"Optional tours, activities, or water sports not specified in inclusions\", \"Early check-in and late check-out at hotels (subject to availability)\", \"Camera or video fees at attractions, if applicable\", \"Any expenses arising due to flight delays, natural calamities, or unforeseen circumstances\", \"Anything not specifically mentioned under “Tour Inclusions”\"]','[]','[{\"day\": 1, \"meals\": \"N/A\", \"title\": \"Arrival in Bangkok\", \"description\": \"Arrive at Bangkok International Airport, where our representative will warmly welcome you and assist with your transfer to the hotel. After check-in, take time to relax and recover from your journey. You may explore nearby markets, enjoy Thai street food, or simply unwind at the hotel. Bangkok’s vibrant atmosphere, colorful streets, and friendly locals provide a perfect introduction to Thailand. Overnight stay in Bangkok.\", \"accommodation\": \"3-Star Hotel             \"}, {\"day\": 2, \"meals\": \"Breakfast\", \"title\": \"Flight to Phuket | Arrival & Transfer\", \"description\": \"After breakfast, transfer to the airport for your domestic flight to Phuket. On arrival, meet our local representative and proceed to your hotel. Check in and enjoy the rest of the day at leisure. You can relax on the beach, explore Patong’s lively streets, or enjoy optional activities. Phuket’s tropical charm sets the mood for an island holiday. Overnight stay in Phuket.\", \"accommodation\": \"3-Star Hotel          \"}, {\"day\": 3, \"meals\": \"Breakfast & Lunch\", \"title\": \"Full-Day Phi Phi Island Tour with Lunch.\", \"description\": \"Today, enjoy a full-day excursion to the world-famous Phi Phi Islands. Cruise through turquoise waters, admire dramatic limestone cliffs, and visit stunning locations such as Maya Bay and Phi Phi Don. Enjoy swimming, snorkeling, and relaxing on pristine beaches. A delicious lunch is included during the tour. Return to Phuket in the evening with unforgettable island memories.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Transfer from Phuket to Krabi\", \"description\": \"After breakfast, check out from the hotel and proceed towards Krabi by comfortable transfer. Enjoy scenic views along the way as you move from one tropical paradise to another. Upon arrival, check in at your hotel and relax. The remainder of the day is free to explore nearby beaches or enjoy Krabi’s calm and scenic surroundings. Overnight stay in Krabi.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Full-Day Four Island Tour with Lunch (Krabi)\", \"description\": \"Set out for a full-day Four Island tour, visiting some of Krabi’s most beautiful islands including Poda Island, Chicken Island, Tup Island, and Phra Nang Cave Beach. Enjoy snorkeling, swimming, and relaxing on white sandy beaches. A tasty lunch is provided during the tour. Return to your hotel by evening for rest and relaxation.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Flight to Bangkok | Evening Dinner Cruise\", \"description\": \"After breakfast, transfer to the airport for your flight back to Bangkok. Upon arrival, check in to your hotel and relax. In the evening, enjoy a memorable dinner cruise along the river, featuring delicious cuisine, live entertainment, and stunning night views of Bangkok’s illuminated landmarks. Overnight stay in Bangkok.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 7, \"meals\": \"Breakfast\", \"title\": \"Safari World & Marine Park\", \"description\": \"After breakfast, proceed for a full-day visit to Safari World and Marine Park. Enjoy close encounters with wildlife, exciting safari drives, and entertaining animal shows. This fun-filled experience is ideal for families and nature lovers. After a day of adventure, return to the hotel for a restful evening. Overnight stay in Bangkok.\", \"accommodation\": \"3-Star Hotel\"}, {\"day\": 8, \"meals\": \"Breakfast\", \"title\": \"Departure\", \"description\": \"After breakfast, check out from the hotel and transfer to the airport for your onward journey. Depart Thailand with beautiful memories of its vibrant cities, breathtaking islands, rich culture, and warm hospitality, bringing an unforgettable holiday experience to a perfect conclusion.\", \"accommodation\": \"N/A\"}]','\"\"','[\"Thailand\"]','[\"City Tours\", \"Luxury Experiences\", \"Cultural Tours\", \"Water Activities\"]',NULL,NULL,NULL,0,1,'2025-12-22 09:05:20','2025-12-22 11:17:18'),(28,329,'ultimate-10-day-east-asia-combo-thailand-malaysia-singapore-expedition','Ultimate 10-Day East Asia Combo: Thailand, Malaysia & Singapore Expedition','','','Experience the best of East Asia in one seamless 9-night, 10-day journey. This curated combo package takes you through the dazzling highlights of Thailand, Malaysia, and Singapore, combining modern cityscapes with tropical island escapes. \n\nYour adventure begins in Thailand, where you\'ll explore the vibrant streets of Bangkok and the sun-drenched beaches of Pattaya. Enjoy a high-speed excursion to Coral Island for water sports and paragliding before diving into Bangkok’s rich history with a tour of its famous Wats (temples). \n\nNext, fly to Singapore, the \"Heart of Asia.\" Discover the iconic Merlion Park, take a cable car to Sentosa Island, and witness the spectacular Wings of Time show. \n\nThe journey concludes in Malaysia, featuring the ultra-modern Petronas Twin Towers in Kuala Lumpur and the breezy heights of Genting Highlands. Experience the cultural depth of the Batu Caves and the ancient Indo-Moorish architecture of the capital city.',0.00,NULL,1,0,NULL,'10 days',NULL,'10','',0.00,0,'January, February, March, November, December','','[\"/uploads/tours/ultimate-10-day-east-asia-combo-thailand-malaysia-singapore-expedition/tour_1769509785722.jpg\", \"/uploads/tours/ultimate-10-day-east-asia-combo-thailand-malaysia-singapore-expedition/tour_1769509912008.jpg\", \"/uploads/tours/ultimate-10-day-east-asia-combo-thailand-malaysia-singapore-expedition/tour_1769509961354.jpg\", \"/uploads/tours/ultimate-10-day-east-asia-combo-thailand-malaysia-singapore-expedition/tour_1769510026278.jpg\"]','[\"Thailand: Coral Island speed boat tour, Bangkok city & temple exploration\", \"Singapore: Sentosa Island, Madame Tussauds, and Marina Bay sights\", \"Malaysia: Genting Highland cable car ride and Kuala Lumpur landmarks\", \"Comfort: Stay in handpicked 3-star accommodations throughout the trip\"]','[\"Flights: Roundtrip airfare is included in this package\", \"Accommodations: 9 nights of 3-star hotel stays: 2 nights in Bangkok, 2 nights in Pattaya, 2 nights in Singapore, and 3 nights in Kuala Lumpur\", \"Thailand Sightseeing: Temple and City tour of Bangkok and a full excursion to Coral Island\", \"Singapore Sightseeing: Comprehensive Singapore city tour and Sentosa Island package including a 1-way cable car ride, Madame Tussauds, Wings of Time, and Images of Singapore\", \"Malaysia Sightseeing: Kuala Lumpur city tour and a visit to Genting Highlands\", \"Guide Services: A professional English-speaking guide to escort you throughout the trip\", \"Transfers: All scheduled tours and ground transfers are covered\", \"Meals: Meals are provided as specifically mentioned in the daily itinerary\", \"Visas & Taxes: Includes Singapore visa on arrival, Thailand and Malaysia visa fees, plus government taxes and service charges\"]','[\"Personal Expenses: Any items of a personal nature such as laundry, shopping, tips, and telephone bills\", \"Additional Meals: Any meals or food items not explicitly listed in the \\\"includes\\\" section\", \"Unscheduled Transfers: Any personal transfers or charges incurred due to halting\", \"Surcharges: Potential hotel surcharges during special events, exhibitions, or holiday dates\", \"Unspecified Items: Any other item or activity not mentioned under the \'Package Includes\' heading\"]','[]','[{\"day\": 1, \"meals\": \"\", \"title\": \"Arrival Bangkok – Transfer to Pattaya\", \"description\": \"Arrive at Bangkok Airport\\n\\nDrive to Pattaya (approx. 2 hours)\\n\\nFree time on arrival\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 2, \"meals\": \"Breakfast & Lunch\", \"title\": \"Coral Island Tour\", \"description\": \"Half-day Coral Island excursion\\n\\nWater sports & paragliding (optional)\\n\\nEvening at leisure in Pattaya\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 3, \"meals\": \"Breakfast\", \"title\": \"Pattaya – Bangkok City & Temple Tour\", \"description\": \"Transfer from Pattaya to Bangkok\\n\\nBangkok city & temple tour (Wat Po, Wat Traimit)\\n\\nFree time for shopping\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 4, \"meals\": \"Breakfast\", \"title\": \"Bangkok – Free Day\", \"description\": \"Day at leisure for shopping or optional tours\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 5, \"meals\": \"Breakfast\", \"title\": \"Bangkok – Singapore\", \"description\": \"Transfer to airport & fly to Singapore\\n\\n\\nFree time at Orchard Road\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 6, \"meals\": \"Breakfast\", \"title\": \"Singapore City Tour & Sentosa Island\", \"description\": \"Singapore city tour (Merlion Park, Marina Bay, Civic District)\\n\\nSentosa Island tour with attractions & cable car ride\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 7, \"meals\": \"Breakfast\", \"title\": \"Singapore – Kuala Lumpur (By Coach)\", \"description\": \"Coach transfer from Singapore to Kuala Lumpur\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 8, \"meals\": \"Breakfast\", \"title\": \"Kuala Lumpur City Tour\", \"description\": \"Half-day KL city tour\\n\\nVisit Petronas Twin Towers, King’s Palace, National Mosque, Independence Square, Batu Caves (view)\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 9, \"meals\": \"Breakfast\", \"title\": \"Genting Highlands Tour\", \"description\": \"Full-day Genting Highlands excursion\\n\\nCable car ride & Batu Caves visit\", \"accommodation\": \"3 star Hotel\"}, {\"day\": 10, \"meals\": \"Breakfast\", \"title\": \"Departure\", \"description\": \"Transfer to Kuala Lumpur Airport\\n\\nFly back home\", \"accommodation\": \"3 star Hotel\"}]','\"\"','[\"Thailand\"]','[\"Cultural Tours\", \"City Tours\", \"Water Activities\"]',NULL,NULL,'{}',0,1,'2026-01-27 10:33:51','2026-01-27 10:33:51');
